texttool_globals_dialog_message___abort_loging_cancel_confirmation_text = TextObject(bs_BA="Želite li prekinuti prijavu?", cs_CZ="Chcete zrušit svou registraci?", da_DK="Vil du afbryde login?", de_DE="Möchtest du die Anmeldung abbrechen?", el_GR="Θέλετε να ματαιώσετε τη σύνδεση (log in);", en_GB="Would you like to cancel the login?", es_ES="¿Cancelar el inicio de sesión?", fi_FI="Haluatko keskeyttää kirjautumisen?", fr_FR="Souhaitez-vous annuler la connexion?", hr_HR="Želite li prekinuti prijavu?", hu_HU="Meg szeretnéd szakítani a bejelentkezést?", it_IT="Annullare il login?", nl_NL="Wil je het aanmelden annuleren?", no_NO="Vil du avbryte påloggingen?", pl_PL="Anulować logowanie?", pt_PT="Queres cancelar o registo?", ro_RO="Doriţi într-adevăr să întrerupeţi autentificarea?", ru_RU="Хотите отменить вход?", sk_SK="Chcete zrušiť prihlásenie?", sl_SI="Ali res želite prekiniti prijavo?", sr_RS="Da li želite da prekinete prijavu?", sv_SE="Vill du avbryta inloggningen`?", tr_TR="Oturum açmayı iptal etmek istiyor musun?", uk_UA="Хочете скасувати вхід?")
texttool_globals_dialog_message___add_online_user_privacy_warning_dialog = TextObject(bs_BA="Za prijavu vašeg myAudi korisnika je neophodna veza sa internetom. Želite li sada\nuspostaviti vezu sa internetom?", cs_CZ="Pro přihlášení svým uživatelem myAudi potřebujete připojení k internetu. Chcete\nnyní vytvořit připojení k internetu?", da_DK="Internetforbindelse er nødvendigt for at kunne logge din myAudi-bruger på. Vil du\noprette internetforbindelse nu?", de_DE="Für die Anmeldung deines myAudi Nutzers ist eine Internetverbindung notwendig.\nMöchtest du jetzt eine Internetverbindung herstellen?", el_GR="Για τη σύνδεση (log in) με τον λογαριασμό σας χρήστη myAudi απαιτείται σύνδεση με\nτο διαδίκτυο. Θέλετε να δημιουργήσετε τώρα μια σύνδεση με το διαδίκτυο;", en_GB="An Internet connection is required to log in with your myAudi user. Would you like\nto establish an Internet connection now?", es_ES="Para iniciar sesión con su usuario myAudi necesita conexión a Internet. ¿Desea\nconectarse a Internet?", fi_FI="myAudi-käyttäjätilille kirjautumiseen tarvitaan internetyhteys. Haluatko nyt\nmuodostaa internetyhteyden?", fr_FR="Une connexion Internet est requise pour pouvoir vous connecter à votre profil\nutilisateur myAudi. Souhaitez-vous établir une connexion Internet maintenant?", hr_HR="Za prijavu myAudi korisničkog računa potrebna je veza s internetom. Želite li sada\nuspostaviti vezu s internetom?", hu_HU="A myAudi felhasználód bejelentkezéséhez internetkapcsolat szükséges. Szeretnél\nmost csatlakozni az internethez?", it_IT="Per effettuare il login all'utente myAudi è necessario un collegamento internet.\nDesidera stabilire adesso un collegamento internet?", nl_NL="Voor het aanmelden van je myAudi gebruiker is verbinding met het internet vereist.\nWil je nu verbinding met het internet maken?", no_NO="Du må ha internettforbindelse for å logge på myAudi-brukeren din. Vil du opprette\ninternettforbindelse nå?", pl_PL="Do zalogowania Twojego użytkownika myAudi wymagane jest połączenie z\nInternetem. Czy chcesz nawiązać połączenie z Internetem teraz?", pt_PT="Para fazer login com o teu utilizador myAudi, é necessária uma ligação à Internet.\nQueres estabelecer agora uma ligação à Internet?", ro_RO="Pentru autentificarea utilizatorului myAudi este necesară o conexiune la Internet.\nDoriţi să realizaţi acum o conexiune la Internet?", ru_RU="Для входа пользователя myAudi требуется интернет-соединение. Хотите\nустановить интернет-соединение сейчас?", sk_SK="Na prihlásenie vášho používateľa myAudi sa vyžaduje internetové pripojenie. Chcete\nteraz vytvoriť internetové pripojenie?", sl_SI="Za prijavo uporabnika myAudi je potrebna internetna povezava. Ali želite zdaj\nvzpostaviti internetno povezavo?", sr_RS="Za prijavu vašeg myAudi korisnika je neophodna veza sa internetom. Da li želite\nsada uspostaviti vezu sa internetom?", sv_SE="För att logga in med din myAudi-användare behövs en internetanslutning. Vill du\nansluta till internet nu?", tr_TR="myAudi kullanıcınla oturum açmak için bir internet bağlantısı gereklidir. Şimdi\ninternete bağlanmak istiyor musun?", uk_UA="Для входу користувача myAudi потрібне з’єднання з Інтернетом. Бажаєте\nвстановити з’єднання з Інтернетом зараз?")
texttool_globals_dialog_message___confirm_spin_privacy_warning_dialog = TextObject(bs_BA="Za dodatnu provjeru vašeg myAudi PIN-a je neophodna veza sa internetom. Želite li\nsada uspostaviti vezu sa internetom?", cs_CZ="Pro další kontrolu svého PINu myAudi potřebujete připojení k internetu. Chcete nyní\nvytvořit připojení k internetu?", da_DK="Internetforbindelse er nødvendigt for at kunne kontrollere din myAudi-pinkode\nyderligere. Vil du oprette internetforbindelse nu?", de_DE="Für eine weitere Prüfung deiner myAudi PIN wird eine Internetverbindung benötigt.\nMöchtest du jetzt eine Internetverbindung herstellen?", el_GR="Για τον περαιτέρω έλεγχο του myAudi PIN σας απαιτείται σύνδεση με το διαδίκτυο.\nΘέλετε να δημιουργήσετε τώρα μια σύνδεση με το διαδίκτυο;", en_GB="An Internet connection is required for a further check of your myAudi PIN. Would\nyou like to establish an Internet connection now?", es_ES="Una comprobación más exhaustiva de su PIN myAudi requiere conexión a Internet.\n¿Desea conectarse a Internet?", fi_FI="myAudi-PIN-koodin tarkastamista varten tarvitaan internetyhteys. Haluatko nyt\nmuodostaa internetyhteyden?", fr_FR="Une connexion Internet est requise pour une vérification complémentaire de votre\ncode PIN myAudi. Souhaitez-vous établir une connexion Internet maintenant?", hr_HR="Za daljnju provjeru vašeg myAudi PIN-a potrebna je internetska veza. Želite li sada\nuspostaviti internetsku vezu?", hu_HU="A myAudi PIN-kódod további ellenőrzéséhez internetkapcsolat szükséges. Szeretnél\nmost csatlakozni az internethez?", it_IT="Per un'ulteriore verifica del Suo PIN myAudi è necessario un collegamento internet.\nDesidera stabilire adesso un collegamento internet?", nl_NL="Om je myAudi pincode verder te controleren, is verbinding met het internet vereist.\nWil je nu verbinding met het internet maken?", no_NO="En ny kontroll av myAudi-PIN krever internettforbindelse. Vil du opprette\ninternettforbindelse nå?", pl_PL="Do dalszej kontroli Twojego kodu PIN myAudi wymagane jest połączenie z\nInternetem. Czy chcesz nawiązać połączenie z Internetem teraz?", pt_PT="Para continuar a verificar o teu PIN myAudi, é necessária uma ligação à Internet.\nQueres estabelecer agora uma ligação à Internet?", ro_RO="Pentru verificarea suplimentară a codului PIN myAudi este necesară o conexiune la\nInternet. Doriţi să realizaţi acum o conexiune la Internet?", ru_RU="Для дальнейшей проверки PIN-кода myAudi требуется интернет-соединение.\nУстановить интернет-соединение сейчас?", sk_SK="Pre opätovnú kontrolu kódu PIN myAudi je potrebné internetové pripojenie. Chcete\nteraz vytvoriť internetové pripojenie?", sl_SI="Za dodatno preverjanje vaše PIN-kode myAudi je potrebna internetna povezava. Ali\nželite zdaj vzpostaviti internetno povezavo?", sr_RS="Za dodatnu proveru vašeg myAudi PIN-a neophodna je veza sa internetom. Da li\nželite sada uspostaviti vezu sa internetom?", sv_SE="För att ytterligare kontrollera din myAudi-PIN-kod behövs en internetanslutning.\nVill du ansluta till internet nu?", tr_TR="myAudi PIN'ini daha ayrıntılı kontrol etmek için bir internet bağlantısı gereklidir.\nŞimdi internete bağlanmak istiyor musun?", uk_UA="Для подальшої перевірки PIN-коду myAudi потрібне з'єднання з Інтернетом.\nБажаєте встановити з'єднання зараз?")
texttool_globals_dialog_message___delete_user_error_primary_user = TextObject(bs_BA="Glavni korisnik se ne može ukloniti. Prijavite se kao glavni korisnik da biste mogli\nizvršiti postupak brisanja ili resetujte sistem na fabričke postavke.", cs_CZ="Hlavního uživatele nelze odstranit. Přihlaste se jako hlavní uživatel a proveďte\nproces odstranění nebo obnovte tovární nastavení systému.", da_DK="Primær bruger kan ikke fjernes. Log på som primær bruger for at gennemføre\nsletningen, eller nulstil systemet til fabriksindstillingerne.", de_DE="Der Hauptnutzer kann nicht entfernt werden. Bitte melde dich als Hauptnutzer an,\num den Löschvorgang vorzunehmen, oder setze das System auf die\nWerkseinstellungen zurück.", el_GR="Δεν είναι εφικρή η αφαίρεση του βασικού χρήστη. Συνδεθείτε (log in) ως βασικός\nχρήστης, για να προβείτε στη διαδικασία διαγραφής ή επαναφέρετε το σύστημα στις\nεργοστασιακές ρυθμίσεις.", en_GB="The key user cannot be removed. Please log in as a key user to delete the key user or\nreset the system to factory settings.", es_ES="El usuario principal no se puede eliminar. Para borrarlo, inicie sesión como usuario\nprincipal o restablezca los ajustes de fábrica del sistema.", fi_FI="Pääkäyttäjää ei voida poistaa. Kirjaudu pääkäyttäjänä poistamisen suorittamiseksi\ntai palauta järjestelmä tehdasasetuksiin.", fr_FR="L'utilisateur principal ne peut pas être supprimé. Veuillez vous connecter en tant\nqu'utilisateur principal pour procéder à la suppression ou rétablissez les réglages\nd'usine du système.", hr_HR="Glavni korisnik se ne može ukloniti. Prijavite se kao glavni korisnik kako biste izvršili\nbrisanje ili poništite sustav na tvorničke postavke.", hu_HU="A főfelhasználó nem távolítható el. Jelentkezz be főfelhasználóként a törlési\nfolyamat végrehajtásához, vagy állítsd vissza a rendszert a gyári beállításokra.", it_IT="Non è possibile eliminare l'utente principale. Effettuare il login come utente\nprincipale per eseguire la cancellazione o ripristinare la configurazione iniziale del\nsistema.", nl_NL="De hoofdgebruiker kan niet worden verwijderd. Meld je als hoofdgebruiker aan om\nzelf het wissingsproces over te nemen of zet het systeem terug in de\nfabrieksinstellingen.", no_NO="Kan ikke fjerne hovedbrukeren. Logg på som hovedbruker for å utføre slettingen,\neller tilbakestill systemet til fabrikkinnstillingene.", pl_PL="Nie można usunąć użytkownika głównego. Zaloguj się jako użytkownik główny, aby\ndokonać usunięcia lub przywrócić ustawienia fabryczne systemu.", pt_PT="O utilizador principal não pode ser eliminado. Por favor, faz login como utilizador\nprincipal para realizares a eliminação ou repõe as configurações de fábrica do\nsistema.", ro_RO="Utilizatorul principal nu poate fi şters. Autentificaţi-vă ca utilizator principal, pentru\na efectua operaţia de ştergere sau resetaţi sistemul la setările din fabrică.", ru_RU="Основной пользователь не может быть удален. Чтобы выполнить удаление,\nвойдите в систему под именем основного пользователя или сбросьте заводские\nнастройки.", sk_SK="Hlavného používateľa nie je možné odstrániť. Prosím, prihláste sa ako hlavný\npoužívateľ, aby ste odstránili alebo resetovali systém na výrobné nastavenia.", sl_SI="Glavnega uporabnika ni mogoče odstraniti. Prijavite se kot glavni uporabnik, da\nizvedete brisanje ali sistem resetirate na tovarniške nastavitve.", sr_RS="Glavni korisnik ne može da se ukloni. Prijavite se kao glavni korisnik da biste mogli\nizvršiti postupak brisanja ili resetujte sistem na fabrička podešavanja.", sv_SE="Huvudanvändaren kan inte tas bort. Logga in som huvudanvändare för att ta bort\nanvändaren eller återställ systemet till fabriksinställningarna.", tr_TR="Ana kullanıcı kaldırılamaz. Silme işlemini gerçekleştirmek için lütfen ana kullanıcı\nolarak oturum aç veya sistemi fabrika ayarlarına sıfırla.", uk_UA="Основного користувача не можна видалити. Увійдіть як основний користувач,\nщоб виконати процес видалення або скинути систему до заводських\nналаштувань.")
texttool_globals_dialog_message___delete_user_warning_active_primary_user = TextObject(bs_BA="Želite li zaista ukloniti aktivnog glavnog korisnika %1 iz\novog vozila? Time će biti izgubljene vaše spremljene individualne postavke i učitan\ngostujući korisnik. Status glavnog korisnika ostaje.", cs_CZ="Opravdu chcete odstranit aktivního hlavního uživatele %1 z\ntohoto vozidla? Vaše uložená individuální nastavení ve vozidle budou ztracena a\nbude načten hostující uživatel. Stav hlavního uživatele zůstane zachován.", da_DK="Vil du virkelig fjerne den aktive primære bruger %1 fra\ndenne bil? Dermed går dine gemte individuelle indstillinger i bilen tabt, og\ngæstebrugeren indlæses. Statussen som primær bruger bibeholdes.", de_DE="Möchtest du den aktiven Hauptnutzer %1 wirklich aus\ndiesem Fahrzeug entfernen? Damit gehen deine gespeicherten individuellen\nEinstellungen im Fahrzeug verloren und der Gastnutzer wird geladen. Der\nHauptnutzerstatus bleibt bestehen.", el_GR="Θέλετε σίγουρα να αφαιρέσετε τον ενεργό βασικό χρήστη\n%1 από αυτό το όχημα; Έτσι θα χαθούν οι αποθηκευμένες\nσας στο όχημα προσωπικές ρυθμίσεις και θα γίνει φόρτωση του χρήστη επισκέπτη. Η\nιδιότητα ως βασικός χρήστης συνεχίζει να υφίσταται.", en_GB="Do you really want to remove the active key user %1 from\nthis vehicle? This will remove your saved custom settings and the guest account will\nbe loaded. The status of the key user will remain in place.", es_ES="¿Realmente desea eliminar el usuario principal activo %1\nde este vehículo? En ese caso se perderán sus ajustes personales memorizados en\nel vehículo y se cargará el usuario invitado. El estado del usuario principal se\nmantiene.", fi_FI="Haluatko varmasti poistaa aktiivisen pääkäyttäjän %1 tästä\nautosta? Samalla tallentamasi yksilölliset asetukset häviävät ja vieraskäyttäjä\nlatautuu. Pääkäyttäjän asema säilyy.", fr_FR="Souhaitez-vous vraiment supprimer de ce véhicule l'utilisateur principal actif\n%1? Tous vos réglages personnels mémorisés dans le\nvéhicule seront ainsi perdus et le profil utilisateur invité sera chargé. Le statut\nd'utilisateur principal reste conservé.", hr_HR="Želite li aktivnog glavnog korisnika %1 uistinu ukloniti iz\novog vozila? Tako će se u vozilu izgubiti vaše pohranjene individualne postavke i\nučitat će se gost korisnik. Status glavnog korisnika ostaje sačuvan.", hu_HU="Biztosan el szeretnéd távolítani az aktív %1 főfelhasználót\nebből a járműből? A járműben mentett egyéni beállításaid ekkor elvesznek, és a\nvendégfelhasználó töltődik be. A főfelhasználói státusz továbbra is megmarad.", it_IT="Eliminare l'utente principale attivo %1 da questa vettura?\nIn questo modo le impostazioni individuali memorizzate nella vettura andranno\nperse e verrà caricato l'utente ospite. Lo stato di utente principale rimane invariato.", nl_NL="Wil je de actieve hoofdgebruiker %1 echt uit dit voertuig\nverwijderen? Dan gaan je opgeslagen individuele instellingen in het voertuig\nverloren en wordt de gastgebruiker geladen. De hoofdgebruikerstatus blijft\nbestaan.", no_NO="Er du sikker på at du vil fjerne den aktive hovedbrukeren\n%1 fra denne bilen? Da går de lagrede personlige\ninnstillingene dine tapt, og gjestebrukeren lastes inn. Statusen som hovedbruker\nbeholdes.", pl_PL="Czy na pewno chcesz usunąć aktywnego użytkownika głównego\n%1 z tego pojazdu? Spowoduje to, że Twoje zapisane\nustawienia indywidualne zostaną utracone i zostanie wczytany użytkownik-gość.\nStatus użytkownika głównego zostanie zachowany.", pt_PT="Queres mesmo remover o utilizador principal ativo %1\ndeste veículo? Deste modo os teus ajustes pessoais memorizados no veículo\ndesaparecerão e será carregado o utilizador convidado. O estado do utilizador\nprincipal mantém-se.", ro_RO="Doriţi într-adevăr să ştergeţi utilizatorul principal activ %1\ndin acest autovehicul? Astfel, setările individuale memorate în autovehicul se vor\npierde şi se va încărca utilizatorul oaspete. Starea utilizatorului principal se\npăstrează.", ru_RU="Вы действительно хотите удалить активного основного пользователя\n%1 из этого автомобиля? Это приведет к потере\nсохраненных вами индивидуальных настроек и загрузке гостевого\nпользователя. Статус основного пользователя сохранится.", sk_SK="Skutočne chcete odstrániť aktívneho primárneho používateľa\n%1 z tohto vozidla? Tým sa vaše uložené individuálne\nnastavenia vo vozidle stratia a načíta sa používateľ typu hosť. Stav hlavného\npoužívateľa zostáva zachovaný.", sl_SI="Ali res želite aktivnega glavnega uporabnika %1 odstraniti\niz tega vozila? S tem boste izgubili shranjene individualne nastavitve v vozilu in\nnaložen bo gostujoči uporabnik. Status glavnega uporabnika se ohrani.", sr_RS="Da li zaista želite da uklonite aktivnog glavnog korisnika\n%1 iz ovog vozila? Time će biti izgubljena vaša sačuvana\nindividualna podešavanja i učitan gostujući korisnik. Status glavnog korisnika\nostaje.", sv_SE="Vill du verkligen ta bort den aktiva huvudanvändaren %1\nfrån detta fordon? I så fall går dina sparade individuella inställningar i fordonet\nförlorade och gästanvändaren laddas. Huvudanvändarens status blir kvar.", tr_TR="Aktif ana kullanıcıyı %1 bu araçtan gerçekten kaldırmak\nistiyor musun? Böylece araçtaki kaydedilmiş kişisel ayarların kaybolur ve misafir\nkullanıcı yüklenir. Ana kullanıcı statüsü aynı kalır.", uk_UA="Ви дійсно хочете видалити активного основного користувача\n%1 з цього автомобіля? Ваші збережені індивідуальні\nналаштування в транспортному засобі будуть втрачені, а гостьовий користувач\nбуде завантажений. Статус основного користувача залишиться.")
texttool_globals_dialog_message___delete_user_warning_active_user = TextObject(bs_BA="Da li zaista želite ukloniti aktivnog korisnika %1 iz ovog\nvozila? Na taj način će biti izgubljene Vaše memorisane individualne postavke i\nučitava se korisnik gost.", cs_CZ="Chcete opravdu odstranit aktivního uživatele %1 z tohoto\nvozidla? Tím se všechna Vaše uložená individuální nastavení ztratí a načte se\nuživatel Host.", da_DK="Vil du virkelig fjerne den aktive bruger %1 fra denne bil?\nDermed går dine gemte individuelle indstillinger tabt, og gæstebrugeren indlæses.", de_DE="Möchtest du den aktiven Nutzer %1 wirklich aus diesem\nFahrzeug entfernen? Damit gehen deine gespeicherten individuellen Einstellungen\nverloren und der Gastnutzer wird geladen.", el_GR="Θέλετε σίγουρα να αφαιρέσετε τον ενεργό χρήστη %1 από\nαυτό το όχημα; Έτσι θα χαθούν οι αποθηκευμένες σας προσωπικές ρυθμίσεις και θα\nγίνει φόρτωση του χρήστη επισκέπτη.", en_GB="Do you really want to delete the active user %1 from this\nvehicle? Your stored individual settings will be lost and the guest account will be\nloaded.", es_ES="¿Realmente desea eliminar el usuario activo %1 de este\nvehículo? En ese caso se perderán sus ajustes individuales memorizados y se\ncargará el usuario invitado.", fi_FI="Haluatko varmasti poistaa aktiivisen käyttäjän %1 tästä\nautosta? Samalla tallentamasi yksilölliset asetukset häviävät ja vieraskäyttäjä\nlatautuu.", fr_FR="Souhaitez-vous vraiment supprimer de ce véhicule l'utilisateur actif\n%1? Tous vos réglages personnels mémorisés seront ainsi\nperdus et le profil utilisateur invité sera chargé.", hr_HR="Želite li aktivnog korisnika %1 stvarno ukloniti iz ovog\nvozila? Time će se izgubiti vaše pohranjene individualne postavke i učitat će se\ngost-korisnik.", hu_HU="Biztosan el szeretnéd távolítani az aktív felhasználót %1\nebből a járműből? A mentett egyéni beállításaid ekkor elvesznek, és a\nvendégfelhasználó töltődik be.", it_IT="Eliminare l'utente attivo %1 da questa vettura? In questo\nmodo le impostazioni individuali memorizzate andranno perse e verrà caricato\nl'utente ospite.", nl_NL="Wil je de actieve gebruiker %1 echt uit dit voertuig\nverwijderen? Hiermee gaan de opgeslagen individuele instellingen verloren en\nwordt de gastgebruiker geladen.", no_NO="Er du sikker på at du vil fjerne den aktive brukeren %1 fra\ndenne bilen? Da går de lagrede personlige innstillingene dine tapt, og\ngjestebrukeren lastes inn.", pl_PL="Czy na pewno chcesz usunąć aktywnego użytkownika %1 z\ntego pojazdu? Spowoduje to, że zapisane ustawienia indywidualne zostaną utracone\ni zostanie wczytany użytkownik-gość.", pt_PT="Queres mesmo remover o utilizador ativo %1 deste\nveículo? Desta forma, os teus ajustes individuais memorizados perder-se-ão e será\ncarregado o utilizador convidado.", ro_RO="Doriţi să ştergeţi într-adevăr utilizatorul activ %1 din acest\nautovehicul? Astfel, setările individuale memorate se vor pierde şi se va încărca\nutilizatorul oaspete.", ru_RU="Вы действительно хотите удалить активного пользователя\n%1 из этого автомобиля? Это приведет к потере\nсохраненных Вами индивидуальных настроек и загрузке гостевого\nпользователя.", sk_SK="Skutočne chcete z tohto vozidla odstrániť aktívneho používateľa\n%1? Vaše uložené individuálne nastavenia sa potom stratia\na načíta sa používateľ typu Hosť.", sl_SI="Ali res želite aktivnega uporabnika %1 odstraniti iz tega\nvozila? S tem boste izgubili shranjene individualne nastavitve in naložen bo\ngostujoči uporabnik.", sr_RS="Da li zaista želite da uklonite aktivnog korisnika %1 iz ovog\nvozila? Na taj način će biti izgubljena vaša sačuvana individualna podešavanja,\nkorisnik gost će biti učitan.", sv_SE="Vill du verkligen ta bort den aktiva användaren %1 ur detta\nfordon? Dina sparade individuella inställningar går då förlorade och\ngästanvändaren laddas.", tr_TR="Aktif kullanıcıyı %1 bu araçtan gerçekten kaldırmak istiyor\nmusun? Böylece kaydedilmiş kişisel ayarların kaybolur ve misafir kullanıcı yüklenir.", uk_UA="Дійсно видалити активного користувача %1 з цього\nавтомобіля? У такому разі збережені індивідуальні настройки буде втрачено й\nбуде завантажено користувача-гостя.")
texttool_globals_dialog_message___delete_user_warning_user = TextObject(bs_BA="Da li zaista želite ukloniti korisnika %1 iz ovog vozila? Na\ntaj način će biti izgubljene Vaše memorisane individualne postavke.", cs_CZ="Chcete opravdu odstranit uživatele %1 z tohoto vozidla?\nTím se uložená individuální nastavení ztratí.", da_DK="Vil du virkelig fjerne brugeren %1 fra denne bil? Dermed\ngår de gemte individuelle indstillinger tabt.", de_DE="Möchtest du den Nutzer %1 wirklich aus diesem Fahrzeug\nentfernen? Damit gehen die gespeicherten individuellen Einstellungen verloren.", el_GR="Θέλετε σίγουρα να αφαιρέσετε τον ενεργό χρήστη %1 από\nαυτό το όχημα; Έτσι θα χαθούν οι αποθηκευμένες σας προσωπικές ρυθμίσεις.", en_GB="Do you really want to delete the user %1 from this vehicle?\nThe stored individual settings will be lost.", es_ES="¿Realmente desea eliminar el usuario %1 de este vehículo?\nEn ese caso se perderán los ajustes individuales memorizados.", fi_FI="Haluatko varmasti poistaa käyttäjän %1 tästä autosta?\nSamalla tallennetut yksilölliset asetukset häviävät.", fr_FR="Souhaitez-vous vraiment supprimer de ce véhicule l'utilisateur\n%1? Tous vos réglages personnels mémorisés seront ainsi\nperdus.", hr_HR="Želite li korisnika %1 stvarno ukloniti iz ovog vozila? Time\nće se izgubiti pohranjene individualne postavke.", hu_HU="Biztosan el szeretnéd távolítani a felhasználót %1 ebből a\njárműből? A mentett egyéni beállítások ekkor elvesznek.", it_IT="Eliminare l'utente %1 da questa vettura? In questo modo\nle impostazioni individuali memorizzate andranno perse.", nl_NL="Wil je gebruiker %1 uit dit voertuig verwijderen? Hiermee\ngaan de opgeslagen individuele instellingen verloren.", no_NO="Er du sikker på at du vil fjerne brukeren %1 fra denne\nbilen? Da går de lagrede personlige innstillingene tapt.", pl_PL="Czy na pewno chcesz usunąć aktywnego użytkownika %1 z\ntego pojazdu? Spowoduje to, że zapisane ustawienia indywidualne zostaną\nutracone.", pt_PT="Queres mesmo remover o utilizador %1 deste veículo?\nDesta forma, os ajustes individuais memorizados perder-se-ão.", ro_RO="Doriţi să ştergeţi într-adevăr utilizatorul activ %1 din acest\nautovehicul? Astfel, setările individuale memorate se vor pierde.", ru_RU="Вы действительно хотите удалить пользователя %1 из\nэтого автомобиля? Это приведет к потере сохраненных индивидуальных\nнастроек.", sk_SK="Skutočne chcete z tohto vozidla odstrániť používateľa %1?\nUložené individuálne nastavenia sa potom stratia.", sl_SI="Ali res želite uporabnika %1 odstraniti iz tega vozila? S tem\nboste izgubili shranjene individualne nastavitve.", sr_RS="Da li zaista želite da uklonite korisnika %1 iz ovog vozila?\nNa taj način će biti izgubljena vaša sačuvana individualna podešavanja.", sv_SE="Vill du verkligen ta bort användaren %1 ur detta fordon?\nDina sparade individuella inställningar går då förlorade.", tr_TR="Kullanıcıyı %1 bu araçtan gerçekten kaldırmak istiyor\nmusun? Böylece kaydedilmiş kişisel ayarlar kaybolur.", uk_UA="Дійсно видалити активного користувача %1 з цього\nавтомобіля? У такому разі збережені індивідуальні настройки буде втрачено.")
texttool_globals_dialog_message___face_recognition_data_activeuser_not_deleted = TextObject(bs_BA="Vaši podaci za detekciju lica nisu mogli biti izbrisani. Postupak brisanja se nastavlja.\nUkoliko to ne bude funkcionisalo, obratite se vašem Audi partneru.", cs_CZ="Vaše data z rozpoznávání obličeje nebylo možné vymazat. Proces mazání bude\npokračovat. Pokud se to nepodaří, obraťte se na svého partnera Audi.", da_DK="Dine ansigtsgenkendelsesdata kunne ikke slettes. Sletning fortsættes. Hvis det ikke\nvirker, skal du henvende dig til din Audi partner.", de_DE="Deine Gesichtserkennungsdaten konnten nicht gelöscht werden. Der Löschvorgang\nwird fortgesetzt. Solle das nicht funktionieren, wende dich bitte an deinen Audi\nPartner.", el_GR="Δεν ήταν εφικτή η διαγραφή των δεδομένων σας αναγνώρισης προσώπου. Η\nδιαδικασία διαγραφής θα συνεχιστεί. Εάν αυτό δεν είναι εφικτό, απευθυνθείτε στον\nεξουσιοδοτημένο Συνεργάτη Audi που σας εξυπηρετεί.", en_GB="Your face recognition data could not be deleted. The deletion procedure will be\ncontinued. If this does not work, please contact your Audi Partner.", es_ES="No se han podido borrar los datos de su reconocimiento facial. El proceso para\nborrarlos continúa. Si no funciona, diríjase a su Concesionario Audi.", fi_FI="Kasvojentunnistustietojasi ei voitu poistaa. Poistamista jatketaan. Jos se ei toimi,\nota yhteyttä Audi-jälleenmyyjääsi.", fr_FR="Vos données de reconnaissance faciale n'ont pas pu être effacées. L’effacement se\npoursuit. Si cela ne fonctionne pas, veuillez contacter votre Partenaire Audi.", hr_HR="Podaci o prepoznavanju vašeg lica nisu izbrisani. Postupak brisanja se nastavlja. Ako\nne bude funkcioniralo, obratite se svom Audi partneru.", hu_HU="Az arcfelismerési adataid nem törölhetők. A törlési folyamat folytatódik. Ha nem\nműködik, fordulj Audi partneredhez.", it_IT="Non è stato possibile cancellare i Suoi dati di riconoscimento facciale. Il processo di\ncancellazione continua. Se non dovesse funzionare, si rivolga al Suo partner Audi.", nl_NL="Je gezichtsherkenningsgegevens konden niet worden gewist. Het wissen wordt\nvoortgezet. Neem contact op met je Audi Partner als dit niet werkt.", no_NO="Data for ansiktsgjenkjenning ble ikke slettet. Slettingen fortsetter. Kontakt\nAudi-forhandleren hvis det ikke går.", pl_PL="Nie można usunąć danych rozpoznawania Twojej twarzy. Usuwanie będzie\nkontynuowane. Gdyby się nie udało, skontaktuj się z dealerem Audi.", pt_PT="Os teus dados de reconhecimento facial não podem ser apagados.O procedimento\nde eliminação prosseguirá. Caso isto não funcione, por favor, contacta o teu\nConcessionário Audi.", ro_RO="Datele dumneavoastră de recunoaştere facială nu au putut fi şterse. Procesul de\nştergere continuă. Dacă nu funcţionează, adresaţi-vă partenerului Audi.", ru_RU="Ваши данные распознавания лица не могут быть удалены. Процесс удаления\nбудет продолжен. Если это не сработает, обратитесь к вашему партнеру Audi.", sk_SK="Vaše údaje o rozpoznávaní tváre sa nepodarilo vymazať. Proces mazania pokračuje.\nAk by to nefungovalo, obráťte sa, prosím, na svojho Audi partnera.", sl_SI="Vaših podatkov za prepoznavanje obraza ni bilo mogoče izbrisati. Brisanje se bo\nnadaljevalo. Če to ne bo delovalo, se obrnite na pooblaščenega partnerja Audi.", sr_RS="Brisanje vaših podataka za prepoznavanje lica nije bilo moguće. Postupak brisanja\nse nastavlja. Ako to ne bude funkcionisalo, obratite se vašem Audi partneru.", sv_SE="Dina ansiktsigenkänningsdata kunde inte raderas. Raderingsförsöket fortsätter.\nKontakta din Audi-partner om det inte fungerar.", tr_TR="Yüz tanıma verilerin silinemedi. Silme işlemi devam ediyor. Eğer bu işe yaramazsa\nlütfen Audi yetkili servisine başvur.", uk_UA="Ваші дані розпізнавання обличчя не вдалося видалити. Процес видалення буде\nпродовжено. Якщо це не допоможе, зверніться до вашого партнера Audi.")
texttool_globals_dialog_message___face_recognition_data_not_deleted = TextObject(bs_BA="Određeni podaci za detekciju lica nisu mogli biti izbrisani. Postupak brisanja se\nnastavlja. Ukoliko to ne bude funkcionisalo, obratite se vašem Audi partneru.", cs_CZ="Některá data z rozpoznávání obličeje nebylo možné vymazat. Proces mazání bude\npokračovat. Pokud se to nepodaří, obraťte se na svého partnera Audi.", da_DK="Nogle ansigtsgenkendelsesdata kunne ikke slettes. Sletning fortsættes. Hvis det\nikke virker, skal du henvende dig til din Audi partner.", de_DE="Einige Gesichtserkennungsdaten konnten nicht gelöscht werden. Der Löschvorgang\nwird fortgesetzt. Solle das nicht funktionieren, wende dich bitte an deinen Audi\nPartner.", el_GR="Δεν ήταν εφικτή η διαγραφή ορισμένων δεδομένων αναγνώρισης προσώπου σας. Η\nδιαδικασία διαγραφής θα συνεχιστεί. Εάν αυτό δεν είναι εφικτό, απευθυνθείτε στον\nεξουσιοδοτημένο Συνεργάτη Audi που σας εξυπηρετεί.", en_GB="Some face recognition data could not be deleted. The deletion procedure will be\ncontinued. If this does not work, please contact your Audi Partner.", es_ES="No se han podido borrar algunos datos del reconocimiento facial. El proceso para\nborrarlos continúa. Si no funciona, diríjase a su Concesionario Audi.", fi_FI="Joitakin kasvojentunnistustietoja ei voitu poistaa. Poistamista jatketaan. Jos se ei\ntoimi, ota yhteyttä Audi-jälleenmyyjääsi.", fr_FR="Certaines données de reconnaissance faciale n'ont pas pu être effacées.\nL’effacement se poursuit. Si cela ne fonctionne pas, veuillez contacter votre\nPartenaire Audi.", hr_HR="Neki podaci o prepoznavanju lica nisu izbrisani. Postupak brisanja se nastavlja. Ako\nne bude funkcioniralo, obratite se svom Audi partneru.", hu_HU="Egyes arcfelismerési adataid nem törölhetők. A törlési folyamat folytatódik. Ha\nnem működik, fordulj Audi partneredhez.", it_IT="Non è stato possibile cancellare alcuni dati di riconoscimento facciale. Il processo di\ncancellazione continua. Se non dovesse funzionare, si rivolga al Suo partner Audi.", nl_NL="Sommige gezichtsherkenningsgegevens konden niet worden gewist. Het wissen\nwordt voortgezet. Neem contact op met je Audi Partner als dit niet werkt.", no_NO="Noen data for ansiktsgjenkjenning ble ikke slettet. Slettingen fortsetter. Kontakt\nAudi-forhandleren hvis det ikke går.", pl_PL="Nie można usunąć niektórych danych rozpoznawania twarzy. Usuwanie będzie\nkontynuowane. Gdyby się nie udało, skontaktuj się z dealerem Audi.", pt_PT="Alguns dados de reconhecimento facial não podem ser apagados. O procedimento\nde eliminação prosseguirá.Caso isto não funcione, por favor, contacta o teu\nConcessionário Audi.", ro_RO="Unele date de recunoaştere facială nu au putut fi şterse. Procesul de ştergere\ncontinuă. Dacă nu funcţionează, adresaţi-vă partenerului Audi.", ru_RU="Некоторые данные распознавания лица не удалось удалить. Процесс удаления\nбудет продолжен. Если это не поможет, обратитесь к вашему партнеру Audi.", sk_SK="Niektoré údaje o rozpoznávaní tváre sa nepodarilo vymazať. Proces mazania\npokračuje. Ak by to nefungovalo, obráťte sa, prosím, na svojho Audi partnera.", sl_SI="Nekaterih podatkov za prepoznavanje obraza ni bilo mogoče izbrisati. Brisanje se bo\nnadaljevalo. Če to ne bo delovalo, se obrnite na pooblaščenega partnerja Audi.", sr_RS="Brisanje određenih podataka za prepoznavanje lica nije bilo moguće. Postupak\nbrisanja se nastavlja. Ako to ne bude funkcionisalo, obratite se vašem Audi\npartneru.", sv_SE="Vissa ansiktsigenkänningsdata kunde inte raderas. Raderingsförsöket fortsätter.\nKontakta din Audi-partner om det inte fungerar.", tr_TR="Bazı yüz tanıma verileri silinemedi. Silme işlemi devam ediyor. Eğer bu işe\nyaramazsa lütfen Audi yetkili servisine başvur.", uk_UA="Деякі дані розпізнавання обличчя не вдалося видалити. Процес видалення буде\nпродовжено. Якщо це не допоможе, зверніться до вашого партнера Audi.")
texttool_globals_dialog_message___fr_scan_error_ambiguous_recognition_message = TextObject(bs_BA="Vaše lice ili slično lice je već povezano s još jednim korisnikom.", cs_CZ="Váš obličej nebo podobný je již spojen s jiným uživatelem.", da_DK="Dit ansigt eller et lignende ansigt er allerede forbundet med en anden bruger.", de_DE="Dein Gesicht oder ein ähnliches Gesicht ist bereits mit einem weiteren Nutzer\nverbunden.", el_GR="Το πρόσωπό σας ή ένα παρόμοιο πρόσωπο είναι ήδη συνδεδεμένο με έναν άλλο\nλογαριασμό χρήστη.", en_GB="Your face or a similar face is already linked to another user.", es_ES="Su cara o una cara parecida ya está asociada a otro usuario.", fi_FI="Kasvosi tai samalta näyttävät kasvot on jo yhdistetty toiseen käyttäjätiliin.", fr_FR="Votre visage ou un visage similaire est déjà associé à un autre profil utilisateur.", hr_HR="Vaše ili neko drugo slično lice već su povezani s drugim korisnikom.", hu_HU="Az arcod vagy egy hasonló arc már egy másik felhasználóhoz van kapcsolva.", it_IT="Il Suo volto o un volto simile è già associato a un altro utente.", nl_NL="Je gezicht of een vergelijkbaar gezicht is al verbonden met een andere gebruiker.", no_NO="Ansiktet ditt eller et ansikt som ligner, er allerede tilknyttet en annen bruker.", pl_PL="Twoja lub podobna twarz jest już powiązana z innym użytkownikiem.", pt_PT="O teu rosto ou um rosto idêntico já está associado a outro utilizador.", ro_RO="Faţa dumneavoastră sau o faţă asemănătoare este deja asociată cu un alt utilizator.", ru_RU="Ваше лицо или похожее лицо уже связано с другим пользователем.", sk_SK="Vaša tvár alebo podobná tvár je už prepojená s iným používateľom.", sl_SI="Vaš ali podoben obraz je že povezan z drugim uporabnikom.", sr_RS="Vaše lice ili slično lice je već povezano sa još jednim korisnikom.", sv_SE="Ditt ansikte eller ett liknande ansikte är redan kopplat till en annan användare.", tr_TR="Yüzün veya benzer bir yüz zaten başka bir kullanıcıya bağlı.", uk_UA="Ваше обличчя або схоже обличчя вже пов'язане з іншим користувачем.")
texttool_globals_dialog_message___fr_scan_error_failure_to_acquire_sample_message = TextObject(bs_BA="Detekcija lica nije bila moguća. Uvjerite se da je vaše lice dobro vidljivo.", cs_CZ="Nebylo možné rozpoznat obličej. Ujistěte se, že je váš obličej dobře viditelný.", da_DK="Der kunne ikke genkendes noget ansigt. Sørg for, at dit ansigt er synligt.", de_DE="Es konnte kein Gesicht erkannt werden. Bitte stelle sicher, dass dein Gesicht gut\nsichtbar ist.", el_GR="Δεν ήταν εφικτή η αναγνώριση προσώπου. Βεβαιωθείτε ότι το πρόσωπό σας είναι\nευδιάκριτο.", en_GB="A face could not be recognised. Please make sure that your face is clearly visible.", es_ES="No se ha podido detectar la cara. Por favor, asegúrese de que la cara se vea bien.", fi_FI="Kasvoja ei tunnistettu. Varmista, että kasvosi ovat hyvin nähtävissä.", fr_FR="Aucun visage n'a pu être reconnu. Veuillez vous assurer que votre visage est bien\nvisible.", hr_HR="Nije bilo moguće prepoznati lice, uvjerite se da se vaše lice dobro vidi.", hu_HU="Nem lehetett felismerni az arcot. Győződj meg arról, hogy az arcod jól látható.", it_IT="Non è stato possibile riconoscere alcun volto. Si assicuri che il Suo volto sia ben\nvisibile.", nl_NL="Er kon geen gezicht worden herkend. Zorg ervoor dat je gezicht goed zichtbaar is.", no_NO="Gjenkjenner ikke noe ansikt. Sørg for at ansiktet er godt synlig.", pl_PL="Nie można rozpoznać twarzy. Upewnij się, że Twoja twarz jest dobrze widoczna.", pt_PT="Não é possível reconhecer qualquer rosto. Por favor, certifica-te que o teu rosto está\nbem visível.", ro_RO="Nu a putut fi recunoscută nicio faţă. Asiguraţi-vă că faţa dumneavoastră este bine\nvizibilă.", ru_RU="Не удалось распознать лицо. Убедитесь, что ваше лицо хорошо видно.", sk_SK="Tvár sa nepodarilo rozpoznať. Prosím, uisti sa, že je vaša tvár dobre viditeľná.", sl_SI="Ni bilo mogoče prepoznati obraza. Preverite, da je vaš obraz dobro viden.", sr_RS="Prepoznavanje lica nije bilo moguće. Postarajte se da vaše lice bude dobro vidljivo.", sv_SE="Inget ansikte kunde identifieras. Se till att ditt ansikte syns ordentligt.", tr_TR="Hiçbir yüz tanınamadı. Lütfen yüzünün net bir şekilde göründüğünden emin ol.", uk_UA="Не вдалося розпізнати обличчя. Переконайтеся, що ваше обличчя добре видно.")
texttool_globals_dialog_message___fr_scan_error_failure_to_compute_match_message = TextObject(bs_BA="Postarajte se da gledate pravo u unutrašnji retrovizor i da vaše lice nije prekriveno.", cs_CZ="Ujistěte se prosím, že se díváte do vnitřního zpětného zrcátka a že nemáte zakrytý\nobličej.", da_DK="Sørg for, at du kigger direkte ind i bakspejlet, og at dit ansigt ikke er dækket til.", de_DE="Bitte stelle sicher, dass du gerade in den Innenspiegel schaust und dein Gesicht\nnicht bedeckt ist.", el_GR="Βεβαιωθείτε ότι αυτήν τη στιγμή κοιτάζετε προς τον εσωτερικό καθρέφτη και ότι το\nπρόσωπό σας δεν είναι καλυμμένο.", en_GB="Please make sure that you are looking at the interior mirror and your face is not\ncovered.", es_ES="Asegúrese de mirar directamente al retrovisor interior y de que su cara no está\ncubierta.", fi_FI="Varmista, että katsot suoraan sisäpeiliin ja että kasvojesi edessä ei ole mitään.", fr_FR="Veuillez regarder droit dans le rétroviseur intérieur et veillez à ce que votre visage\nne soit pas couvert.", hr_HR="Morate gledati ravno u unutrašnje zrcalo i vaše lice ne smije biti pokriveno.", hu_HU="Gondoskodj róla, hogy egyenesen nézz bele a belső visszapillantó tükörbe, és az\narcod ne legyen takarva.", it_IT="Si assicuri di guardare direttamente nello specchio retrovisore interno e di non\navere il volto coperto.", nl_NL="Zorg ervoor dat je recht in de binnenspiegel kijkt en je gezicht niet bedekt is.", no_NO="Pass på at du ser rett i det innvendige speilet, og at ansiktet ikke er tildekket.", pl_PL="Upewnij się, że patrzysz właśnie w lusterko wewnętrzne, a Twoja twarz nie jest\nzakryta.", pt_PT="Por favor, certifica-te que olhas a direito para o espelho interior e que o teu rosto\nnão está oculto.", ro_RO="Asiguraţi-vă că priviţi acum în oglinda interioară şi că nu aveţi faţa acoperită.", ru_RU="Убедитесь, что вы смотрите прямо в зеркало заднего вида и ваше лицо не\nзакрыто.", sk_SK="Prosím, uistite sa, že sa priamo pozeráte do vnútorného zrkadla a vaša tvár nie je\nzakrytá.", sl_SI="Preverite, da gledate naravnost v notranje ogledalo in vaš obraz ni zakrit.", sr_RS="Postarajte se da gledate pravo u unutrašnji retrovizor i da vaše lice nije prekriveno.", sv_SE="Se till att titta rakt in i innerbackspegeln och att ditt ansikte inte är övertäckt.", tr_TR="Lütfen düz olarak dikiz aynasına doğru baktığından ve yüzünün kapalı olmadığından\nemin ol.", uk_UA="Переконайтеся, що ви дивитеся прямо в дзеркало заднього виду і ваше обличчя\nне закрите.")
texttool_globals_dialog_message___fr_scan_error_process_took_too_long_message = TextObject(bs_BA="Postupak je trajao suviše dugo.", cs_CZ="Proces trval příliš dlouho.", da_DK="Handlingen tog for lang tid.", de_DE="Der Vorgang hat zu lange gedauert.", el_GR="Η διαδικασία διήρκεσε πολύ.", en_GB="The procedure took too long.", es_ES="El proceso ha durado demasiado.", fi_FI="Tapahtuma kesti liian kauan.", fr_FR="La procédure a pris trop de temps.", hr_HR="Postupak je trajao predugo.", hu_HU="A folyamat túl sokáig tartott.", it_IT="L'operazione ha richiesto troppo tempo.", nl_NL="De procedure heeft te lang geduurd.", no_NO="Prosessen har tatt for lang tid.", pl_PL="Proces trwał zbyt długo.", pt_PT="O procedimento demorou demasiado.", ro_RO="Procesul a durat prea mult.", ru_RU="Процесс занял слишком много времени.", sk_SK="Proces trval príliš dlho.", sl_SI="Postopek je trajal predolgo.", sr_RS="Postupak je trajao suviše dugo.", sv_SE="Processen tog för lång tid.", tr_TR="İşlem çok uzun sürdü.", uk_UA="Процес тривав занадто довго.")
texttool_globals_dialog_message___personalize_user_dialog_message = TextObject(bs_BA="Personalizirajte Vašeg korisnika tek kada Vašeg korisnika budete htjeli zaštititi\npomoću PIN-a.", cs_CZ="Pokud chcete svého uživatele chránit pomocí kódu PIN, nejprve si ho prosím\npřizpůsobte.", da_DK="Individualiser først din bruger, hvis du gerne vil beskytte din bruger med en\npinkode.", de_DE="Bitte personalisiere zuerst deinen Nutzer, wenn du deinen Nutzer mit einer PIN\nschützen möchtest.", el_GR="Εξατομικεύστε πρώτα τον λογαριασμό χρήστη σας, εάν θέλετε να τον προστατεύσετε\nμε PIN.", en_GB="Please customise your user first if you wish to protect your user with a PIN.", es_ES="Personalice primero su usuario si desea protegerlo con un PIN.", fi_FI="Yksilöi ensin käyttäjäprofiilisi, jos haluat suojata käyttäjätilisi PIN-koodilla.", fr_FR="Veuillez d'abord personnaliser votre profil utilisateur si vous souhaitez le protéger\navec un code PIN.", hr_HR="Prvo personalizirajte svoj korisnički račun ako ga želite zaštititi PIN-om.", hu_HU="Először végezd el a felhasználód személyre szabását, ha PIN-kóddal szeretnéd\nvédeni a felhasználódat.", it_IT="Prima personalizzare l'utente, se si desidera proteggerlo con un PIN.", nl_NL="Personaliseer eerst je gebruiker als je deze met een pincode wilt beschermen.", no_NO="Hvis du vil beskytte brukeren din med en PIN-kode, må du først tilpasse brukeren.", pl_PL="Jeśli użytkownik ma być chroniony kodem PIN, musisz go najpierw spersonalizować.", pt_PT="Por favor, personaliza primeiro o teu utilizador caso desejes proteger o teu\nutilizador com um PIN.", ro_RO="Vă rugăm să vă personalizaţi întâi utilizatorul, dacă doriţi să vă protejaţi utilizatorul\ncu un PIN.", ru_RU="Если вы хотите защитить своего пользователя с помощью PIN-кода, сначала\nперсонализируйте его.", sk_SK="Prosím, najskôr personalizujte vášho používateľa, aby ste ho chránili pomocou PIN\nkódu.", sl_SI="Najprej personalizirajte uporabnika, če ga želite zaščititi s PIN-kodo.", sr_RS="Personalizaciju vašeg korisnika izvršite tek kada vašeg korisnika želite da zaštitite\npomoću PIN-a.", sv_SE="Anpassa först din användare om du vill skydda användaren med en PIN-kod.", tr_TR="Kullanıcını bir PIN ile korumak istiyorsan lütfen önce kullanıcını kişiselleştir.", uk_UA="Якщо ви хочете захистити свого користувача за допомогою PIN-коду, будь ласка,\nспочатку персоналізуйте його.")
texttool_globals_dialog_message___personalize_user_fleetblocked = TextObject(bs_BA="Ne možete personalizirati vašeg korisnika, jer ovim vozilom upravlja operater\nvoznog parka.", cs_CZ="Nemůžete si přizpůsobit svého uživatele, protože toto vozidlo je řízeno\nprovozovatelem vozového parku.", da_DK="Du kan ikke personalisere din bruger, da denne bil styres af en flådeejer.", de_DE="Du kannst deinen Nutzer nicht personalisieren, da dieses Fahrzeug von einem\nFlottenbetreiber gesteuert wird.", el_GR="Δεν μπορείτε να εξατομικεύσετε τον λογαριασμό σας χρήστη, διότι η διαχείριση\nαυτού του οχήματος γίνεται από έναν φορέα διαχείρισης στόλου.", en_GB="You cannot personalise your user as this vehicle is managed by a fleet operator.", es_ES="No puede personalizar su usuario porque este vehículo lo gestiona el operador de la\nflota.", fi_FI="Et voi yksilöidä käyttäjäprofiiliasi, koska tätä autoa hallinnoi autokaluston\nylläpitäjä.", fr_FR="Vous ne pouvez pas personnaliser votre profil utilisateur car ce véhicule est contrôlé\npar un gestionnaire de flotte.", hr_HR="Ne možete individualizirati svoj korisnički račun jer vozilom upravlja administrator\nvoznog parka.", hu_HU="Nem szabhatod személyre a felhasználódat, mivel ezt a járművet egy flottakezelő\nirányítja.", it_IT="Non può personalizzare il Suo utente perché questa vettura è gestita da un\namministratore di flotta.", nl_NL="Je kunt je gebruiker niet personaliseren omdat deze auto door een\nwagenparkbeheerder wordt beheerd.", no_NO="Du kan ikke tilpasse denne brukeren fordi bilen administreres av en bilparkoperatør.", pl_PL="Nie możesz spersonalizować swojego użytkownika, ponieważ ten pojazd jest\nsterowany przez operatora floty.", pt_PT="Não podes personalizar o teu utilizador, pois o teu veículo é gerido por um Gestor\nde frotas.", ro_RO="Nu vă puteţi personaliza utilizatorul, deoarece acest autovehicul este controlat de\nun administrator de flotă.", ru_RU="Вы не можете персонализировать своего пользователя, так как этот автомобиль\nуправляется оператором автопарка.", sk_SK="Nemôžete personalizovať svojho používateľa, pretože toto vozidlo je spravované\nprevádzkovateľom flotily.", sl_SI="Vašega uporabnika ni mogoče personalizirati, ker to vozilo upravlja upravitelj\nvoznega parka.", sr_RS="Ne možete personalizovati vašeg korisnika, jer ovim vozilom upravlja operater\nvoznog parka.", sv_SE="Du kan inte anpassa din användare eftersom bilen styrs av en vagnparksoperatör.", tr_TR="Bu araç bir filo operatörü tarafından kontrol edildiğinden kullanıcını\nkişiselleştiremezsin.", uk_UA="Ви не можете персоналізувати свого користувача, оскільки цей автомобіль\nкерується оператором автопарку.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_with_logbook = TextObject(bs_BA="Želite li ukloniti glavnog korisnika za ovo vozilo? Na taj način svi korisnici gube\npripadajuća ovlaštenja. Deaktivira se usluga „Online dnevnik vožnje“.", cs_CZ="Chcete odstranit hlavního uživatele pro toto vozidlo? Tím všichni další uživatelé\nztratí svá příslušná oprávnění. Služba \"Online kniha jízd\" se deaktivuje.", da_DK="Vil du fjerne den primære bruger for denne bil? Dermed mister alle brugere deres\ntilhørende beføjelser. Tjenesten \"Onlinekørebog\" deaktiveres.", de_DE="Möchtest du den Hauptnutzer für dieses Fahrzeug entfernen? Damit verlieren alle\nNutzer ihre zugehörigen Berechtigungen. Der Dienst „Online-Fahrtenbuch“ wird\ndeaktiviert.", el_GR="Θέλετε να αφαιρέσετε τον βασικό χρήστη για αυτό το όχημα; Έτσι θα χάσουν όλοι οι\nχρήστες τις αντίστοιχες εξουσιοδοτήσεις τους. Η υπηρεσία \"Online ημερολόγιο\nδιαδρομών\" θα απενεργοποιηθεί.", en_GB="Would you like to remove the key user for this vehicle? All users will lose their\ncorresponding authorisations. The online logbook service will be deactivated.", es_ES="¿Desea eliminar el usuario principal de este vehículo? En ese caso todos los usuarios\nperderán sus permisos asociados. El servicio \"Registro de viajes online\"se\ndesactivará.", fi_FI="Haluatko poistaa tämän auton pääkäyttäjän? Samalla kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät. Palvelu \"online-ajopäiväkirja\" deaktivoidaan.", fr_FR="Souhaitez-vous supprimer l'utilisateur principal de ce véhicule? Tous les utilisateurs\nperdent ainsi leurs autorisations correspondantes. Le service «Carnet de route en\nligne» sera désactivé.", hr_HR="Želite li ukloniti glavnog korisnika za ovo vozilo? Tako svi korisnici gube svoja\npripadajuća ovlaštenja. Usluga \"Online knjiga vožnji\" se deaktivira.", hu_HU="El szeretnéd távolítani ennek a járműnek a főfelhasználóját? Ezzel az összes\nfelhasználó elveszíti a megfelelő jogosultságait. Az „Online\nútnyilvántartás”szolgáltatás kikapcsolódik.", it_IT="Eliminare l'utente principale per questa vettura? In questo modo tutti gli utenti\nperdono le relative autorizzazioni. Il servizio \"Giornale di bordo online\" viene\ndisattivato.", nl_NL="Wil je de hoofdgebruiker van dit voertuig verwijderen? Hiermee verliezen alle\ngebruikers hun autorisaties. De dienst \"online rittenboek\" wordt gedeactiveerd.", no_NO="Vil du fjerne hovedbrukeren for denne bilen? Da vil alle brukerne miste sine\nrettigheter. Tjenesten Online-kjørebok blir deaktivert.", pl_PL="Czy chcesz usunąć użytkownika głównego tego pojazdu? Spowoduje to utratę\nuprawnień przez wszystkich użytkowników. Usługa „Książka przejazdów online”\nzostanie wyłączona.", pt_PT="Queres remover o utilizador principal deste veículo? Desta forma, todos os\nutilizadores perdem as suas respetivas autorizações. O serviço \"Livro de registos de\nviagem online\" será desativado.", ro_RO="Doriţi să eliminaţi utilizatorul principal pentru acest autovehicul? Astfel, toţi\nutilizatorii îşi pierd drepturile aferente. Serviciul \"Foaie de parcurs online\" este\ndezactivat.", ru_RU="Хотите удалить основного пользователя для этого автомобиля? В результате все\nпользователи потеряют соответствующие права доступа. Служба «Онлайн\nбортовой журнал» будет отключена.", sk_SK="Chcete odstrániť hlavného používateľa tohto vozidla? To znamená, že všetci\npoužívatelia stratia svoje priradené oprávnenia. Služba „Online kniha jázd“ sa\ndeaktivuje.", sl_SI="Ali želite odstraniti glavnega uporabnika tega vozila? S tem vsi uporabniki izgubijo\npripadajoča pooblastila. Storitev \"Spletni dnevnik voženj\" bo deaktivirana.", sr_RS="Da li želite da uklonite glavnog korisnika za ovo vozilo? Na taj način svi korisnici\ngube svoja pripadajuća ovlašćenja. Usluga „Onlajn knjižica vožnji“ se deaktivira.", sv_SE="Vill du ta bort huvudanvändaren för detta fordon? Då förlorar alla användare sina\ntillhörande behörigheter. Tjänsten ”Körjournal online” avaktiveras.", tr_TR="Bu araç için ana kullanıcıyı kaldırmak istiyor musun? Böylece, tüm kullanıcılar ilişkili\nyetkilerini kaybederler. \"Çevrimiçi seyir defteri\" hizmeti devre dışı bırakılır.", uk_UA="Бажаєте видалити основного користувача для цього автомобіля? В результаті всі\nкористувачі втратять відповідні права доступу. Службу «Онлайновий журнал\nпоїздок» буде вимкнено.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_with_privacy_and_logbook = TextObject(bs_BA="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlaštenja. Usluga „Online dnevnik vožnji” će biti deaktivirana.\nUspostavite vezu sa internetom za završetak postupka.", cs_CZ="Mobilní data jsou deaktivovaná. Odstraněním hlavního uživatele ztratí všichni\nuživatelé svá příslušná oprávnění. Služba „Online kniha jízd“ se deaktivuje. Vytvořte\npřipojení k internetu, abyste mohli postup dokončit.", da_DK="Mobildata deaktiveret. Hvis du fjerner den primære bruger, mister alle brugere\nderes tilhørende beføjelser. Tjenesten \"Onlinekørebog\" deaktiveres. Opret\ninternetforbindelse for at afslutte processen.", de_DE="Mobile Daten deaktiviert. Mit dem Entfernen des Hauptnutzers verlieren alle Nutzer\nihre zugehörigen Berechtigungen. Der Dienst „Online-Fahrtenbuch“ wird\ndeaktiviert. Stelle eine Internetverbindung her, um den Vorgang abzuschließen.", el_GR="Τα δεδομένα κινητής τηλεφωνίας είναι απενεργοποιημένα. Με την αφαίρεση του\nβασικού χρήστη θα χάσουν όλοι οι χρήστες τις αντίστοιχες εξουσιοδοτήσεις τους. Η\nυπηρεσία „Online ημερολόγιο διαδρομών“ θα απενεργοποιηθεί. Δημιουργήστε μια\nσύνδεση με το διαδίκτυο για να ολοκληρώσετε τη διαδικασία.", en_GB="Mobile data deactivated. All users will lose their corresponding authorisations\nwhen the key user is removed. The online logbook service will be deactivated.\nPlease establish an Internet connection to complete the process.", es_ES="Datos móviles desactivados. Si elimina el usuario principal, todos los usuarios\nperderán sus permisos asociados. El servicio \"Registro de viajes online\" se\ndesactivará. Conéctese a Internet para finalizar el proceso.", fi_FI="Mobiilidata deaktivoitu. Kun pääkäyttäjä poistetaan, kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät. Online-ajopäiväkirja-palvelu deaktivoidaan. Muodosta\ninternetyhteys suorittaaksesi menettelyn loppuun.", fr_FR="Données mobiles désactivées. Lors de la suppression de l'utilisateur principal, tous\nles utilisateurs perdent leurs autorisations correspondantes. Le service «Carnet de\nroute en ligne» sera désactivé. Établissez une connexion Internet pour terminer la\nprocédure.", hr_HR="Mobilni podaci deaktivirani. S uklanjanjem glavnog korisnika svi korisnici gube svoja\npripadajuća odobrenja. Usluga \"Online knjiga vožnje\" se deaktivira. Uspostavite\ninternetsku vezu kako biste završili postupak.", hu_HU="Mobil adatok kikapcsolva. A főfelhasználó eltávolításával az összes felhasználó\nelveszíti a megfelelő jogosultságait. Az „Online útnyilvántartás”szolgáltatás\nkikapcsolódik. A folyamat befejezéséhez csatlakozz az internethez.", it_IT="Dati mobili disattivati. Eliminando l'utente principale, tutti gli utenti perdono le\nrelative autorizzazioni. Il servizio \"Giornale di bordo online\" viene disattivato.\nCollegarsi a internet per completare la procedura.", nl_NL="Mobiele data gedeactiveerd. Met het verwijderen van de hoofdgebruiker verliezen\nalle gebruikers hun bijbehorende autorisaties. De dienst \"online rittenboek\" wordt\ngedeactiveerd. Breng internetverbinding tot stand om de bewerking af te sluiten.", no_NO="Mobildata er deaktivert. Hvis du fjerner hovedbrukeren, mister alle brukere sine\nrettigheter. Tjenesten «Online-kjørebok» blir deaktivert. Opprett\ninternettforbindelse for å fullføre prosessen.", pl_PL="Dane mobilne wyłączone. Usunięcie użytkownika głównego spowoduje utratę\nuprawnień wszystkich użytkowników. Usługa „Książka przejazdów online” zostanie\nwyłączona. Aby zakończyć proces, nawiąż połączenie z Internetem.", pt_PT="Dados móveis desativados. Com a eliminação do utilizador principal, desaparecem\ntodos os utilizadores e as suas respetivas permissões. O serviço “Livro de registos\nde viagem” será desativado. Estabelece uma ligação à Internet para concluir o\nprocedimento.", ro_RO="Date mobile dezactivate. Prin eliminarea utilizatorului principal, toţi utilizatorii îşi\npierd drepturile aferente. Se dezactivează serviciul \"Foaie de parcurs online\".\nRealizaţi conexiunea la Internet, pentru a finaliza procesul.", ru_RU="Мобильные данные отключены. При удалении основного пользователя все\nпользователи теряют связанные с ним полномочия. Сервис «Онлайн бортовой\nжурнал» деактивирован. Для завершения процесса установите подключение к\nИнтернету.", sk_SK="Mobilné dáta deaktivované. Po odstránení hlavného používateľa stratia všetci\npoužívatelia svoje priradené oprávnenia. Služba „Online kniha jázd“ sa deaktivuje.\nNa ukončenie procesu vytvorte internetové pripojenie.", sl_SI="Mobilni podatki deaktivirani. Z odstranitvijo glavnega uporabnika vsi uporabniki\nizgubijo pripadajoča pooblastila. Storitev \"Spletni dnevnik voženj\" bo deaktivirana.\nZa zaključek postopka vzpostavite internetno povezavo.", sr_RS="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlašćenja. Usluga „Onlajn knjižica vožnji” biće deaktivirana.\nUspostavite vezu sa internetom da biste završili postupak.", sv_SE="Mobildata avaktiverad. När du tar bort huvudanvändaren förlorar alla användare\nsina tillhörande behörigheter. Tjänsten ”Körjournal online” avaktiveras. Upprätta en\ninternetanslutning för att slutföra processen.", tr_TR="Mobil veriler devre dışı bırakıldı. Ana kullanıcının kaldırılması ile birlikte tüm\nkullanıcılar ilişkili yetkilerini kaybederler. \"Çevrimiçi seyir defteri\" hizmeti devre dışı\nbırakılır. İşlemi tamamlamak için, bir internet bağlantısı oluştur.", uk_UA="Мобільні дані вимкнено. При видаленні основного користувача всі користувачі\nвтрачають пов'язані з ним повноваження. Служба «Онлайн журнал поїздок»\nдезактивована. Для завершення процесу встановіть підключення до Інтернету.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_with_privacy_without_logbook = TextObject(bs_BA="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlaštenja. Uspostavite vezu sa internetom za završetak postupka.", cs_CZ="Mobilní data deaktivována. Odstraněním hlavního uživatele ztratí všichni uživatelé\nsvá příslušná oprávnění. Vytvořte připojení k internetu, abyste mohli postup\ndokončit.", da_DK="Mobildata deaktiveret. Hvis du fjerner den primære bruger, mister alle brugere\nderes tilhørende beføjelser. Opret internetforbindelse for at afslutte processen.", de_DE="Mobile Daten deaktiviert. Mit dem Entfernen des Hauptnutzers verlieren alle Nutzer\nihre zugehörigen Berechtigungen. Stelle eine Internetverbindung her, um den\nVorgang abzuschließen.", el_GR="Τα δεδομένα κινητής τηλεφωνίας είναι απενεργοποιημένα. Με την αφαίρεση του\nκύριου χρήστη θα χάσουν όλοι οι χρήστες τις αντίστοιχες εξουσιοδοτήσεις τους.\nΔημιουργήστε μια σύνδεση με το διαδίκτυο για να ολοκληρώσετε τη διαδικασία.", en_GB="Mobile data deactivated. All users will lose their corresponding authorisations\nwhen the key user is removed. Establish an Internet connection to complete the\nprocess.", es_ES="Datos móviles desactivados. Si elimina el usuario principal, todos los usuarios\nperderán sus permisos asociados. Conéctese a Internet para finalizar el proceso.", fi_FI="Mobiilidata deaktivoitu. Kun pääkäyttäjä poistetaan, kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät. Muodosta internetyhteys suorittaaksesi menettelyn\nloppuun.", fr_FR="Données mobiles désactivées. Lors de la suppression de l'utilisateur principal, tous\nles utilisateurs perdent leurs autorisations correspondantes. Établissez une\nconnexion Internet pour terminer la procédure.", hr_HR="Mobilni podaci deaktivirani. S uklanjanjem glavnog korisnika svi korisnici gube svoja\npripadajuća odobrenja. Uspostavite internetsku vezu kako biste završili postupak.", hu_HU="Mobiladatok kikapcsolva. A főfelhasználó eltávolításával az összes felhasználó\nelveszíti a megfelelő jogosultságait. A folyamat befejezéséhez csatlakozz az\ninternethez.", it_IT="Dati mobili disattivati. Eliminando l'utente principale, tutti gli utenti perdono le\nrelative autorizzazioni. Collegarsi a internet per completare la procedura.", nl_NL="Mobiele data gedeactiveerd. Met het verwijderen van de hoofdgebruiker verliezen\nalle gebruikers hun bijbehorende autorisaties. Breng een internetverbinding tot\nstand om de bewerking af te sluiten.", no_NO="Mobildata er deaktivert. Hvis du fjerner hovedbrukeren, mister alle brukere sine\nrettigheter. Opprett internettforbindelse for å fullføre prosessen.", pl_PL="Mobilne dane wyłączone. Usunięcie użytkownika głównego spowoduje utratę\nuprawnień przez wszystkich użytkowników. Aby zakończyć proces, nawiąż\npołączenie z Internetem.", pt_PT="Dados móveis desativados. Com a eliminação do utilizador principal, desaparecem\ntodos os utilizadores e as suas respetivas permissões. O serviço “Livro de registos\nde viagem” será desativado. Estabelece uma ligação à Internet para concluir o\nprocedimento.", ro_RO="Date mobile dezactivate. Prin eliminarea utilizatorului principal, toţi utilizatorii îşi\npierd drepturile aferente. Realizaţi conexiunea la Internet, pentru a finaliza\nprocesul.", ru_RU="Мобильные данные отключены. При удалении основного пользователя все\nпользователи теряют связанные с ним полномочия. Для завершения процесса\nустановите подключение к Интернету.", sk_SK="Mobilné dáta deaktivované. Po odstránení hlavného používateľa stratia všetci\npoužívatelia svoje priradené oprávnenia. Na ukončenie procesu vytvorte internetové\npripojenie.", sl_SI="Mobilni podatki deaktivirani. Z odstranitvijo glavnega uporabnika vsi uporabniki\nizgubijo pripadajoča pooblastila. Za zaključek postopka vzpostavite internetno\npovezavo.", sr_RS="Mobilni podaci su deaktivirani. Uklanjanjem glavnog korisnika svi korisnici gube\npripadajuća ovlašćenja. Uspostavite vezu sa internetom da biste završili postupak.", sv_SE="Mobildata avaktiverad. När du tar bort huvudanvändaren förlorar alla användare\nsina tillhörande behörigheter. Upprätta en internetanslutning för att slutföra\nprocessen.", tr_TR="Mobil veriler devre dışı bırakıldı. Ana kullanıcının kaldırılması ile birlikte tüm\nkullanıcılar ilişkili yetkilerini kaybederler. İşlemi tamamlamak için, bir internet\nbağlantısı oluştur.", uk_UA="Мобільні дані вимкнено. При видаленні основного користувача всі користувачі\nвтрачають пов'язані з ним повноваження. Для завершення процесу встановіть\nпідключення до Інтернету.")
texttool_globals_dialog_message___primary_user_reset_warning_dialog_without_logbook = TextObject(bs_BA="Želite li ukloniti glavnog korisnika za ovo vozilo? Na taj način svi korisnici gube\npripadajuća ovlaštenja.", cs_CZ="Chcete odstranit hlavního uživatele pro toto vozidlo? Tím všichni další uživatelé\nztratí svá příslušná oprávnění.", da_DK="Vil du fjerne den primære bruger for denne bil? Dermed mister alle brugere deres\ntilhørende beføjelser.", de_DE="Möchtest du den Hauptnutzer für dieses Fahrzeug entfernen? Damit verlieren alle\nNutzer ihre zugehörigen Berechtigungen.", el_GR="Θέλετε να αφαιρέσετε τον βασικό χρήστη για αυτό το όχημα; Έτσι θα χάσουν όλοι οι\nχρήστες τις αντίστοιχες εξουσιοδοτήσεις τους.", en_GB="Would you like to remove the key user for this vehicle? All users will lose their\ncorresponding authorisations.", es_ES="¿Desea eliminar el usuario principal de este vehículo? En ese caso todos los usuarios\nperderán sus permisos asociados.", fi_FI="Haluatko poistaa tämän auton pääkäyttäjän? Samalla kaikkien käyttäjien asiaan\nliittyvät oikeudet häviävät.", fr_FR="Souhaitez-vous supprimer l'utilisateur principal de ce véhicule? Tous les utilisateurs\nperdent ainsi leurs autorisations correspondantes.", hr_HR="Želite li ukloniti glavnog korisnika za ovo vozilo? Tako svi korisnici gube svoja\npripadajuća ovlaštenja.", hu_HU="El szeretnéd távolítani ennek a járműnek a főfelhasználóját? Ezzel az összes\nfelhasználó elveszíti a megfelelő jogosultságait.", it_IT="Eliminare l'utente principale per questa vettura? In questo modo tutti gli utenti\nperdono le relative autorizzazioni.", nl_NL="Wil je de hoofdgebruiker van dit voertuig verwijderen? Hiermee verliezen alle\ngebruikers hun autorisaties.", no_NO="Vil du fjerne hovedbrukeren for denne bilen? Da vil alle brukerne miste sine\nrettigheter.", pl_PL="Czy chcesz usunąć głównego użytkownika tego pojazdu? Spowoduje to utratę\nuprawnień wszystkich użytkowników.", pt_PT="Queres remover o utilizador principal deste veículo? Desta forma, todos os\nutilizadores perdem as suas respetivas autorizações.", ro_RO="Doriţi să eliminaţi utilizatorul principal pentru acest autovehicul? Astfel, toţi\nutilizatorii îşi pierd drepturile aferente.", ru_RU="Хотите удалить основного пользователя для этого автомобиля? В результате все\nпользователи потеряют соответствующие права доступа.", sk_SK="Chcete odstrániť hlavného používateľa tohto vozidla? To znamená, že všetci\npoužívatelia stratia svoje priradené oprávnenia.", sl_SI="Ali želite odstraniti glavnega uporabnika tega vozila? S tem vsi uporabniki izgubijo\npripadajoča pooblastila.", sr_RS="Da li želite da uklonite glavnog korisnika za ovo vozilo? Na taj način svi korisnici\ngube pripadajuća ovlašćenja.", sv_SE="Vill du ta bort huvudanvändaren för detta fordon? Då förlorar alla användare sina\ntillhörande behörigheter.", tr_TR="Bu araç için ana kullanıcıyı kaldırmak istiyor musun? Böylece, tüm kullanıcılar ilişkili\nyetkilerini kaybederler.", uk_UA="Бажаєте видалити основного користувача для цього автомобіля? В результаті всі\nкористувачі втратять відповідні права доступу.")
texttool_globals_dialog_message___switch_user_to_guest_warning = TextObject(bs_BA="Da li zaista želite promijeniti korisnika? Sistemske postavke i postavke sistema\npomoći za vozača se mogu promijeniti.", cs_CZ="Chcete opravdu přepnout uživatele? Nastavení systému a asistence řidiče se mohou\nzměnit.", da_DK="Vil du virkelig skifte bruger? System- og førerassistentindstillinger kan ændre sig.", de_DE="Willst du den Nutzer wirklich wechseln? System- und Fahrerassistenzeinstellungen\nkönnen sich ändern.", el_GR="Θέλετε σίγουρα να αλλάξετε τον χρήστη; Ενδέχεται να αλλάξουν οι ρυθμίσεις\nσυστήματος και υποβοήθησης οδηγού.", en_GB="Do you really want to change user? System and driver assist settings may change.", es_ES="¿Realmente desea cambiar de usuario? Los ajustes del sistema y de la asistencia al\nconductor pueden cambiar.", fi_FI="Haluatko varmasti vaihtaa käyttäjää? Järjestelmien ja kuljettajan apujärjestelmien\nasetukset saattavat muuttua.", fr_FR="Souhaitez-vous vraiment changer d'utilisateur? Les réglages du système et des\naides au conducteur peuvent être différents.", hr_HR="Želite li uistinu promijeniti korisnika? Sistemske postavke i postavke potpore za\nvozača mogu se promijeniti.", hu_HU="Valóban felhasználót szeretnél váltani? A rendszer és a vezetőasszisztensek\nbeállításai megváltozhatnak.", it_IT="Cambiare utente? Le impostazioni dei sistemi e dell'assistenza al conducente\npotrebbero cambiare.", nl_NL="Wil je de gebruiker echt vervangen? Systeem- en bestuurdershulpinstellingen\nkunnen veranderen.", no_NO="Er du sikker på at du vil bytte bruker? Systeminnstillinger og innstillinger for\nførerassistentsystemer kan bli endret.", pl_PL="Czy na pewno chcesz zmienić użytkownika? Ustawienia systemu i asysty kierowcy\nmogą ulec zmianie.", pt_PT="Desejas mesmo mudar de utilizador? É possível que os ajustes do sistema e do\ncondutor se alterem.", ro_RO="Doriţi într-adevăr să schimbaţi utilizatorul? Setările de sistem şi asistenţă a\nşoferului se pot modifica.", ru_RU="Вы действительно хотите сменить пользователя? Системные настройки и\nнастройки ассистирующих систем водителя могут измениться.", sk_SK="Skutočne chcete zmeniť používateľa? Nastavenia systému a asistencie vodiča sa\nmôžu zmeniť.", sl_SI="Ali res želite zamenjati uporabnika? Sistemske nastavitve in nastavitve asistenčnih\nsistemov se lahko spremenijo.", sr_RS="Da li zaista želite da izmenite korisnika? Podešavanja sistema i asistencije za vozača\nmogu da se izmene.", sv_SE="Vill du verkligen växla användare? System- och förarassistansinställningar kan\nkomma att ändras.", tr_TR="Kullanıcıyı gerçekten değiştirmek istiyor musun? Sistem ve sürücü yardımı ayarları\ndeğişebilir.", uk_UA="Ви дійсно хочете змінити користувача? Настройки системи та настройки\nдопоміжних систем для водія можуть змінитися.")
texttool_globals_dialog_message___switch_user_to_temporary_user_warning = TextObject(bs_BA="Želite li preći na inkognito korisnika? Sistemske postavke i postavke sistema\nasistencije za vozača se mogu promijeniti. Podaci se neće sačuvati u ovom korisniku.", cs_CZ="Chcete přepnout do anonymního režimu? Nastavení systému a asistence řidiče se\nmůže změnit. U tohoto uživatele nejsou ukládána data.", da_DK="Vil du skifte til inkognitobrugeren? System- og førerassistentindstillinger kan\nændre sig. Der gemmes ikke data på denne bruger.", de_DE="Möchtest du zum Inkognito-Nutzer wechseln? System- und\nFahrassistenzeinstellungen können sich ändern. Daten werden in diesem Nutzer\nnicht gespeichert.", el_GR="Θέλετε να αλλάξετε στον ανώνυμο (incognito) χρήστη; Ενδέχεται να αλλάξουν\nρυθμίσεις συστήματος και υποβοήθησης οδηγού. Σε αυτόν τον λογαριασμό χρήστη\nδεν γίνεται αποθήκευση δεδομένων.", en_GB="Do you want to switch to a temporary user? System and driver assist settings may\nchange. Data is not saved for this user.", es_ES="¿Desea cambiar al usuario incógnito? Esto puede cambiar los ajustes del sistema y\nde la asistencia al conductor. Los datos no se guardan en dicho usuario.", fi_FI="Haluatko vaihtaa Tuntematon-käyttäjäprofiiliin? Järjestelmän ja kuljettajaa\navustavien järjestelmien asetukset voivat muuttua. Tietoja ei tallenneta tällä\nkäyttäjäprofiililla.", fr_FR="Souhaitez-vous passer au profil utilisateur incognito? Les réglages du système et\ndes aides au conducteur peuvent être différents. Les données ne sont pas\nmémorisées dans ce profil utilisateur.", hr_HR="Želite li se prebaciti na inkognito korisnički račun? Sistemske postavke i postavke\npotpora za vozača mogu se promijeniti. Podaci se u ovom korisničkom računu neće\npohraniti.", hu_HU="Inkognitó felhasználóra szeretnél váltani? A rendszer és az asszisztensek beállításai\nmegváltozhatnak. Az adatok nem kerülnek mentésre ebben a felhasználóban.", it_IT="Si desidera passare all'utente in incognito? Le impostazioni dei sistemi e\ndell'assistenza al conducente potrebbero cambiare. I dati non vengono memorizzati\nin questo utente.", nl_NL="Wil je overschakelen op de incognito-gebruiker? De instellingen voor systeem- en\nbestuurdershulp kunnen veranderen. In deze gebruiker worden geen gegevens\nopgeslagen.", no_NO="Vil du bytte til inkognito-brukeren? Da kan systeminnstillinger og innstillinger for\nførerassistentsystemer bli endret. Det lagres ikke data for denne brukeren.", pl_PL="Czy chcesz przełączyć się na użytkownika Incognito? Ustawienia systemu i pomocy\nkierowcy mogą ulec zmianie. Dane tego użytkownika nie są zapisywane.", pt_PT="Queres mudar para o utilizador anónimo? Os ajustes do sistema e da assistência à\ncondução podem sofrer alterações. Os dados não serão memorizados neste\nutilizador.", ro_RO="Doriţi să comutaţi la utilizatorul Incognito? Se pot modifica setările sistemului şi de\nasistenţă a şoferului. Datele nu sunt memorate în acest utilizator.", ru_RU="Хотите переключиться на пользователя инкогнито? Настройки системы и\nсистемы помощи водителю могут измениться. Данные в этом пользователе не\nсохраняются.", sk_SK="Chcete zmenu na inkognito používateľa? Nastavenia systému a podporných\nsystémov sa môžu zmeniť. Dáta sa v tomto používateľovi neukladajú.", sl_SI="Ali želite preklopiti na inkognito uporabnika? Sistemske nastavitve in nastavitve\nasistenčnih sistemov se lahko spremenijo. Podatki se ne shranijo za tega\nuporabnika.", sr_RS="Da li želite da pređete na inkognito korisnika? Podešavanja sistema i asistencije za\nvožnju mogu da se izmene. Podaci se ne čuvaju u ovom korisniku.", sv_SE="Vill du växla till Inkognito-läget? System- och förarassistansinställningar kan\nändras. Data sparas inte på denna användare.", tr_TR="Gizli kullanıcıya geçiş yapmak istiyor musun? Sistem ve sürüş desteği ayarları\ndeğişebilir. Bu kullanıcı için veriler kaydedilmez.", uk_UA="Бажаєте переключитися на користувача інкогніто? Налаштування системи та\nдопомоги водієві можуть змінитися. Дані цього користувача не зберігаються.")
texttool_globals_dialog_message___switch_user_warning = TextObject(bs_BA="Želite li zaista prebaciti na korisnika %1? Postavke sistema\ni pomoći vozaču se mogu promijeniti.", cs_CZ="Opravdu chcete přepnout na uživatele %1? Nastavení\nsystému a asistence řidiče se může změnit.", da_DK="Vil du virkelig skifte til brugeren %1? System- og\nførerassistentindstillinger kan ændre sig.", de_DE="Willst du zum Nutzer %1 wirklich wechseln? System- und\nFahrerassistenzeinstellungen können sich ändern.", el_GR="Θέλετε σίγουρα να αλλάξετε στον λογαριασμό χρήστη %1;\nΕνδέχεται να αλλάξουν οι ρυθμίσεις συστήματος και υποβοήθησης οδηγού.", en_GB="Do you really want to switch to user %1? System settings\nand driver assist settings could change.", es_ES="¿Realmente desea cambiar al usuario %1? Los ajustes del\nsistema y de la asistencia al conductor pueden cambiar.", fi_FI="Haluatko varmasti vaihtaa käyttäjään %1? Järjestelmien ja\nkuljettajan apujärjestelmien asetukset saattavat muuttua.", fr_FR="Souhaitez-vous vraiment passer au profil utilisateur %1?\nLes réglages du système et des aides au conducteur peuvent être différents.", hr_HR="Želite li se uistinu prebaciti na korisnika %1? Mogu se\npromijeniti sistemske postavke i postavke vozila.", hu_HU="Valóban át szeretnél váltani %1 felhasználóra? A rendszer\nés a vezetőasszisztensek beállításai megváltozhatnak.", it_IT="Passare all'utente %1? Le impostazioni dei sistemi e\ndell'assistenza al conducente potrebbero cambiare.", nl_NL="Wil je echt veranderen naar gebruiker %1? Systeem- en\nbestuurdershulpinstellingen zullen mogelijk veranderen.", no_NO="Er du sikker på at du vil bytte til brukeren %1?\nSysteminnstillinger og innstillinger for førerassistentsystemer kan bli endret.", pl_PL="Czy na pewno chcesz zmienić użytkownika %1? Ustawienia\nsystemu i asysty kierowcy mogą ulec zmianie.", pt_PT="Queres mesmo mudar para o utilizador %1? Os ajustes do\nsistema e da assistência à condução podem alterar-se.", ro_RO="Doriţi într-adevăr să schimbaţi la utilizatorul %1? Setările\nde sistem şi asistenţă a şoferului se pot modifica.", ru_RU="Вы действительно хотите переключиться на пользователя\n%1? Системные настройки и настройки ассистирующих\nсистем водителя могут измениться.", sk_SK="Skutočne sa chcete prepnúť na používateľa %1? Nastavenia\nsystému a asistenta vodiča sa môžu zmeniť.", sl_SI="Ali res želite preklopiti na uporabnika %1? Sistemske\nnastavitve in nastavitve asistenčnih sistemov se lahko spremenijo.", sr_RS="Da li zaista želite da izmenite korisnika %1? Podešavanja\nsistema i asistencije za vozača mogu da se izmene.", sv_SE="Vill du verkligen byta till användaren %1? System- och\nförarassistansinställningar kan ändras.", tr_TR="Kullanıcıya %1 gerçekten geçmek istiyor musun? Sistem ve\nsürücü yardımı ayarları değişebilir.", uk_UA="Ви дійсно хочете переключитися на користувача %1?\nНастройки системи та настройки допоміжних систем для водія можуть\nзмінитися.")
texttool_globals_dialog_message___token_missing_default_driver_max_users_dialog_confirm = TextObject(bs_BA="Lista korisnika", cs_CZ="Seznam uživatelů", da_DK="Brugerliste", de_DE="Nutzerliste", el_GR="Λίστα χρηστών", en_GB="User list", es_ES="Lista de usuarios", fi_FI="Käyttäjälista", fr_FR="Liste des utilisateurs", hr_HR="Popis korisnika", hu_HU="Felhasználólista", it_IT="Lista utenti", nl_NL="Gebruikerslijst", no_NO="Brukerliste", pl_PL="Lista użytkowników", pt_PT="Lista de utilizadores", ro_RO="Listă utilizatori", ru_RU="Список пользователей", sk_SK="Zoznam používateľov", sl_SI="Seznam uporabnikov", sr_RS="Lista korisnika", sv_SE="Användarlista", tr_TR="Kullanıcı listesi", uk_UA="Список користувачів")
texttool_globals_dialog_message___token_missing_default_driver_max_users_dialog_message = TextObject(bs_BA="Ova funkcija nije raspoloživa za korisnika-gosta. Već ste dostigli maksimalni broj\nkorisnika. Izbrišite nekog korisnika s popisa korisnika kako biste mogli koristiti ovu\nfunkciju i izvršiti personalizaciju vašeg korisnika.", cs_CZ="Tato funkce není pro hostujícího uživatele k dispozici. Dosáhli jste již maximálního\npočtu uživatelů. Chcete-li tuto funkci použít a přizpůsobit si svého uživatele,\nodstraňte jednoho uživatele ze seznamu uživatelů.", da_DK="Denne funktion er kun tilgængelig for gæstebrugeren. Du har allerede nået det\nmaksimale antal brugere. Slet en bruger fra brugerlisten for at anvende denne\nfunktion og individualisere din bruger.", de_DE="Diese Funktion ist für den Gastnutzer nicht verfügbar. Du hast bereits die maximale\nAnzahl an Nutzern erreicht. Bitte lösche einen Nutzer aus der Nutzerliste, um diese\nFunktion zu nutzen und deinen Nutzer zu personalisieren.", el_GR="Αυτή η λειτουργία δεν είναι διαθέσιμη για τον χρήστη επισκέπτη. Συμπληρώσατε ήδη\nτο μέγιστο πλήθος χρηστών. Διαγράψτε έναν χρήστη από τη λίστα χρηστών, για να\nχρησιμοποιήσετε αυτήν τη λειτουργία και να εξατομικεύσετε τον (λογαριασμό)\nχρήστη σας.", en_GB="This function is not available to guest users. You have reached the maximum\nnumber of users. Please delete a user from the list to use this function and\ncustomise your user.", es_ES="Esta función no está disponible para el usuario invitado. Ya ha alcanzado el número\nmáximo de usuarios. Borre un usuario de la lista para utilizar esta función y\npersonalizar su usuario.", fi_FI="Toiminto ei ole vieraskäyttäjän käytettävissä. Käyttäjien enimmäismäärä on\nsaavutettu. Poista jokin käyttäjä käyttäjäluettelosta, niin voit käyttää tätä\ntoimintoa ja yksilöidä käyttäjäprofiilisi.", fr_FR="Cette fonction n'est pas disponible pour le profil utilisateur invité. Vous avez déjà\natteint le nombre maximal d'utilisateurs. Veuillez supprimer un profil utilisateur de\nla liste pour utiliser cette fonction et personnaliser votre profil utilisateur.", hr_HR="Funkcija nije raspoloživa za gosta korisnika. Već ste dostigli maksimalan broj\nkorisničkih računa. Izbrišite neki od korisničkih računa iz popisa kako biste koristili\novu funkciju i personalizirali svoj korisnički račun.", hu_HU="Ez a funkció nem érhető el a vendégfelhasználó számára. Már elérted a\nfelhasználók maximális számát. Törölj egy felhasználót a felhasználói listáról, hogy\nhasználhasd ezt a funkciót, és személyre szabhasd a felhasználódat.", it_IT="Questa funzione non è disponibile per gli utenti ospiti. È già stato raggiunto il\nnumero massimo di utenti. Cancellare un utente dalla lista per poter utilizzare\nquesta funzione e personalizzare il proprio utente.", nl_NL="Deze functie is niet beschikbaar voor de gastgebruiker. Je hebt het maximale aantal\ngebruikers al bereikt. Verwijder een gebruiker uit de gebruikerslijst om deze functie\nte gebruiken en je gebruiker te personaliseren.", no_NO="Denne funksjonen er ikke tilgjengelig for gjestebrukeren. Du har nådd maksimalt\nantall brukere. Du må slette en bruker fra brukerlisten for å kunne bruke denne\nfunksjonen og tilpasse brukeren din.", pl_PL="Ta funkcja nie jest dostępna dla użytkownika-gościa. Osiągnięto maksymalną liczbę\nużytkowników. Aby skorzystać z tej funkcji i spersonalizować swojego użytkownika,\nusuń użytkownika z listy użytkowników.", pt_PT="Esta função não está disponível para o utilizador convidado. Já tingis-te o número\nmáximo de utilizadores. Por favor, apaga um utilizador da lista de utilizadores para\npoderes utilizar esta função e personalizares o teu utilizador.", ro_RO="Această funcţie este indisponibilă pentru utilizatorul oaspete. Aţi atins deja\nnumărul maxim de utilizatori. Ştergeţi un utilizator din lista de utilizatori, pentru a\nutiliza această funcţie şi a vă personaliza utilizatorul.", ru_RU="Эта функция недоступна для гостевых пользователей. Вы уже достигли\nмаксимального количества пользователей. Пожалуйста, удалите одного из\nпользователей из списка, чтобы воспользоваться этой функцией и\nперсонализировать своего пользователя.", sk_SK="Táto funkcia nie je k dispozícii pre hosťovského používateľa. Dosiahli ste už\nmaximálny počet používateľov. Odstráňte prosím jedného používateľa zo zoznamu\npoužívateľov, aby ste mohli túto funkciu využívať a personalizovať svoj účet.", sl_SI="Ta funkcija ni na voljo za gostujočega uporabnika. Dosegli ste že največje število\nuporabnikov. Za uporabo te funkcije in personalizacijo uporabnika izbrišite enega\nuporabnika s seznama uporabnikov.", sr_RS="Ova funkcija nije dostupna za korisnika gosta. Već ste dostigli maksimalni broj\nkorisnika. Izbrišite nekog korisnika sa liste da biste mogli koristiti funkciju i\npersonalizovati Vašeg korisnika.", sv_SE="Den här funktionen är inte tillgänglig för gästanvändare. Du har redan nått det\nmaximala antalet användare. Ta bort en användare från användarlistan för att\nanvända funktionen och anpassa din användare.", tr_TR="Bu fonksiyon misafir kullanıcı için mevcut değildir. Zaten maksimum kullanıcı\nsayısına ulaştın. Bu fonksiyonu kullanmak ve kullanıcını kişiselleştirmek için, lütfen\nkullanıcı listesinden bir kullanıcıyı sil.", uk_UA="Ця функція недоступна для гостьових користувачів. Ви вже досягли\nмаксимальної кількості користувачів. Будь ласка, видаліть одного з користувачів\nзі списку, щоб скористатися цією функцією та персоналізувати свого\nкористувача.")
texttool_globals_dialog_message___token_missing_default_user_warning = TextObject(bs_BA="Ova funkcija nije raspoloživa za korisnika-gosta. Izvršite personalizaciju vašeg\nkorisnika kako biste mogli koristiti ovu funkciju.", cs_CZ="Tato funkce není pro hostujícího uživatele k dispozici. Chcete-li tuto funkci používat,\npřizpůsobte si prosím svůj uživatelský účet.", da_DK="Denne funktion er kun tilgængelig for gæstebrugeren. Individualiser din bruger for\nat kunne anvende denne funktion.", de_DE="Diese Funktion ist für den Gastnutzer nicht verfügbar. Bitte personalisiere deinen\nNutzer, um diese Funktion nutzen zu können.", el_GR="Αυτή η λειτουργία δεν είναι διαθέσιμη για τον χρήστη επισκέπτη. Εξατομικεύστε τον\n(λογαριασμό) χρήστη σας, για να μπορέσετε να χρησιμοποιήσετε αυτήν τη\nλειτουργία.", en_GB="This function is not available to guest users. Please customise your user to use this\nfunction.", es_ES="Esta función no está disponible para el usuario invitado. Borre su usuario para\npoder utilizar esta función.", fi_FI="Toiminto ei ole vieraskäyttäjän käytettävissä. Yksilöi käyttäjäprofiilisi käyttääksesi\ntoimintoa.", fr_FR="Cette fonction n'est pas disponible pour le profil utilisateur invité. Veuillez\npersonnaliser votre profil utilisateur pour pouvoir utiliser cette fonction.", hr_HR="Ova funkcija nije raspoloživa za gosta korisnika. Personalizirajte svoj korisnički\nračun kako biste koristili ovu funkciju.", hu_HU="Ez a funkció nem érhető el a vendégfelhasználó számára. Szabd személyre a\nfelhasználódat, hogy használhasd ezt a funkciót.", it_IT="Questa funzione non è disponibile per gli utenti ospiti. Si prega di personalizzare il\nproprio utente per poter utilizzare questa funzione.", nl_NL="Deze functie is niet beschikbaar voor de gastgebruiker. Personaliseer je gebruiker\nom deze functie te kunnen gebruiken.", no_NO="Denne funksjonen er ikke tilgjengelig for gjestebrukeren. Du må tilpasse brukeren\ndin for å kunne bruke denne funksjonen.", pl_PL="Ta funkcja nie jest dostępna dla użytkownika-gościa. Aby korzystać z tej funkcji,\nspersonalizuj swojego użytkownika.", pt_PT="Esta função não está disponível para o utilizador convidado. Por favor, personaliza o\nteu utilizador para poderes utilizar esta função.", ro_RO="Această funcţie este indisponibilă pentru utilizatorul oaspete. Personalizaţi-vă\nutilizatorul, pentru a putea utiliza această funcţie.", ru_RU="Эта функция недоступна для гостевых пользователей. Пожалуйста,\nперсонализируйте своего пользователя, чтобы воспользоваться этой функцией.", sk_SK="Táto funkcia nie je k dispozícii pre hosťovského používateľa. Prosím, personalizujte\nsvoj používateľský účet, aby ste mohli túto funkciu používať.", sl_SI="Ta funkcija ni na voljo za gostujočega uporabnika. Za uporabo te funkcije \npersonalizirajte svojega uporabnika.", sr_RS="Ova funkcija nije dostupna za korisnika gosta. Izvršite personalizaciju korisnika da\nbiste mogli koristiti ovu funkciju.", sv_SE="Den här funktionen är inte tillgänglig för gästanvändare. Anpassa din användare för\natt använda funktionen.", tr_TR="Bu fonksiyon misafir kullanıcı için mevcut değildir. Bu fonksiyonu kullanabilmek\niçin, lütfen kullanıcını kişiselleştir.", uk_UA="Ця функція недоступна для гостьових користувачів. Будь ласка, персоналізуйте\nсвого користувача, щоб мати можливість користуватися цією функцією.")
texttool_globals_dialog_message___token_missing_generic_error = TextObject(bs_BA="Došlo je do greške. Pokušajte ponovo kasnije.", cs_CZ="Vyskytla se chyba. Zkuste to prosím znovu později.", da_DK="Fejl opstået. Forsøg igen senere.", de_DE="Es ist ein Fehler aufgetreten. Bitte versuche es später erneut.", el_GR="Προέκυψε σφάλμα. Προσπαθήστε πάλι αργότερα.", en_GB="An error has occurred. Please try again later.", es_ES="Se ha producido un error. Por favor, inténtelo de nuevo más tarde.", fi_FI="Tapahtui virhe. Yritä myöhemmin uudelleen.", fr_FR="Une erreur s'est produite. Veuillez réessayer ultérieurement.", hr_HR="Nastupila je greška. Pokušajte ponovno kasnije.", hu_HU="Hiba lépett fel. Kérünk, próbáld újra.", it_IT="Si è verificato un errore. Si prega di riprovare più tardi.", nl_NL="Er is een fout opgetreden. Probeer het later opnieuw.", no_NO="Det har oppstått en feil. Prøv igjen senere.", pl_PL="Wystąpił błąd. Proszę spróbować ponownie później.", pt_PT="Ocorreu uma falha. Por favor, volta a tentar.", ro_RO="A apărut o eroare. Reîncercaţi mai târziu.", ru_RU="Произошла ошибка. Повторите попытку.", sk_SK="Vyskytla sa chyba. Prosím, pokúste sa o to znovu neskôr.", sl_SI="Prišlo je do napake. Poskusite znova.", sr_RS="Došlo je do greške. Pokušajte ponovo kasnije.", sv_SE="Ett fel har uppstått. Försök igen senare.", tr_TR="Bir hata oluştu. Lütfen daha sonra yeniden dene.", uk_UA="Сталася помилка. Повторіть спробу пізніше.")
texttool_globals_dialog_message___token_missing_generic_error_confirm = TextObject(bs_BA="OK", cs_CZ="OK", da_DK="OK", de_DE="OK", el_GR="OK", en_GB="OK", es_ES="OK", fi_FI="OK", fr_FR="OK", hr_HR="OK", hu_HU="OK", it_IT="OK", nl_NL="OK", no_NO="OK", pl_PL="OK", pt_PT="OK", ro_RO="OK", ru_RU="OK", sk_SK="OK", sl_SI="OK", sr_RS="OK", sv_SE="OK", tr_TR="OK", uk_UA="OK")
texttool_globals_dialog_message___token_missing_offline_user_warning = TextObject(bs_BA="Ova funkcija nije raspoloživa za lokalnog korisnika. Prijavite se preko vašeg myAudi\nnaloga kako biste mogli koristiti funkciju.", cs_CZ="Tato funkce není pro místního uživatele k dispozici. Přihlaste se prosím ke svému\núčtu myAudi, abyste mohli tuto funkci využívat.", da_DK="Denne funktion er ikke tilgængelig for den lokale bruger. Log på med din\nmyAudi-konto for at kunne anvende funktionen.", de_DE="Diese Funktion ist für den lokalen Nutzer nicht verfügbar. Bitte melde dich mit\ndeinem myAudi Account an, um die Funktion nutzen zu können.", el_GR="Αυτή η λειτουργία δεν είναι διαθέσιμη για τον τοπικό χρήστη. Συνδεθείτε (log in) με\nτον λογαριασμό myAudi σας, για να μπορέσετε να χρησιμοποιήσετε αυτήν τη\nλειτουργία.", en_GB="This function is not available to local users. Please log in to your myAudi account to\nuse the function.", es_ES="Esta función no está disponible para el usuario local. Inicie sesión con su cuenta\nmyAudi para poder utilizar la función.", fi_FI="Toiminto ei ole paikallisen käyttäjän käytettävissä. Kirjaudu myAudi-käyttäjätilillesi\nkäyttääksesi toimintoa.", fr_FR="Cette fonction n'est pas disponible pour le profil utilisateur local. Veuillez vous\nconnecter à votre compte myAudi pour pouvoir utiliser la fonction.", hr_HR="Ova funkcija nije raspoloživa za lokalnog korisnika. Prijavite se svojim myAudi\nkorisničkim računom kako biste koristili funkciju.", hu_HU="Ez a funkció a helyi felhasználó számára nem érhető el. Jelentkezz be myAudi\nfiókoddal, hogy használni tudd a funkciót.", it_IT="Questa funzione non è disponibile per gli utenti locali. Effettuare il login con il\nproprio account myAudi per poter utilizzare la funzione.", nl_NL="Deze functie is niet beschikbaar voor de lokale gebruiker. Meld je aan met je\nmyAudi-account om de functie te kunnen gebruiken.", no_NO="Denne funksjonen er ikke tilgjengelig for den lokale brukeren. Du må logge på med\nmyAudi-kontoen din for å kunne bruke funksjonen.", pl_PL="Ta funkcja nie jest dostępna dla użytkownika lokalnego. Aby korzystać z tej funkcji,\nzaloguj się z użyciem swojego konta myAudi.", pt_PT="Esta função não está disponível para o utilizador local. Por favor, faz login com a\ntua conta myAudi para poderes utilizar a função.", ro_RO="Această funcţie este indisponibilă pentru utilizatorul local. Autentificaţi-vă cu\ncontul dumneavoastră myAudi, pentru a putea utiliza funcţia.", ru_RU="Эта функция недоступна для локальных пользователей. Пожалуйста, войдите в\nсвою учетную запись myAudi, чтобы воспользоваться этой функцией.", sk_SK="Táto funkcia nie je k dispozícii pre lokálnych používateľov. Prihláste sa pomocou\nsvojho účtu myAudi, aby ste mohli túto funkciu používať.", sl_SI="Ta funkcija ni na voljo za lokalnega uporabnika. Za uporabo funkcije se prijavite s\nsvojim računom myAudi.", sr_RS="Ova funkcija nije dostupna za lokalnog korisnika. Prijavite se preko Vašeg myAudi\nnaloga da biste mogli koristiti funkciju.", sv_SE="Den här funktionen är inte tillgänglig för den lokala användaren. Logga in med ditt\nmyAudi-konto för att använda funktionen.", tr_TR="Bu fonksiyon yerel kullanıcı için mevcut değildir. Fonksiyonu kullanabilmek için,\nlütfen myAudi hesabınla oturum aç.", uk_UA="Ця функція недоступна для локальних користувачів. Будь ласка, увійдіть у свій\nобліковий запис myAudi, щоб скористатися цією функцією.")
texttool_globals_dialog_message___token_missing_online_user_warning = TextObject(bs_BA="Verificirajte vašeg myAudi korisnika da biste koristili ovu funkciju. U tu svrhu,\nmoraju biti aktivirani mobilni podaci. Kada dodirnete na „Verificirati”, vozilo\nuspostavlja podatkovnu vezu za vrijeme trajanja procesa verificiranja.", cs_CZ="Ověřte si svého uživatele myAudi, abyste mohli tuto funkci používat. K tomu musí\nbýt aktivována mobilní data. Pokud klepnete na položku „Ověřit“, Vaše vozidlo\nnaváže datové připojení na dobu trvání ověřovacího procesu.", da_DK="Verificer din myAudi-bruger for at anvende denne funktion. I den forbindelse skal\nmobildata være aktiveret. Når du trykker på \"Verificer\", opretter din bil en\ndataforbindelse, mens verificeringsprocessen er i gang.", de_DE="Verifiziere deinen myAudi Nutzer, um diese Funktion zu verwenden. Mobile Daten\nmüssen dafür aktiviert sein. Wenn du auf \"Verifizieren\" tippst, wird dein Fahrzeug\neine Datenverbindung für die Dauer des Verifizierungsprozesses aufbauen.", el_GR="Επαληθεύστε τον λογαριασμό χρήστη σας myAudi, για να χρησιμοποιήσετε αυτήν τη\nλειτουργία. Εάν πιέσετε σύντομα το «Επαλήθευση», το όχημά σας θα δημιουργήσει\nμια σύνδεση δεδομένων για τη διάρκεια της διαδικασίας επαλήθευσης.", en_GB="Verify your myAudi user to use this function. This requires mobile data to be\nactivated. If you tap on \"Verify\", your vehicle will establish a data connection for the\nduration of the verification process.", es_ES="Verifique su usuario myAudi para utilizar esta función. Los datos móviles deberán\nestar activados. Si pulsa \"Verificar\", el vehículo establecerá una conexión de datos\nmientras dure el proceso de verificación.", fi_FI="Varmenna myAudi-käyttäjätilisi käyttääksesi toimintoa. Mobiilidatan on oltava\naktivoituna. Kun valitset \"Varmenna\", autosi muodostaa datayhteyden\nvarmennusprosessin ajaksi.", fr_FR="Vérifiez votre profil utilisateur myAudi pour utiliser cette fonction. Les données\nmobiles doivent être activées à cet effet. Si vous appuyez brièvement sur «Vérifier»,\nvotre véhicule établira une connexion de données pour la durée de la procédure de\nvérification.", hr_HR="Verificirajte svoj myAudi korisnički račun kako biste koristili ovu funkciju. Za to mora\nbiti aktivirana funkcija mobilnih podataka. Kada dodirnete \"Verificirati\", vaše će\nvozilo uspostaviti podatkovnu vezu za vrijeme procesa verifikacije.", hu_HU="A funkció használatához ellenőrizd myAudi felhasználódat. Ehhez aktiválnod kell a\nmobiladat-használatot. A „Verify” (Ellenőrizés) gombra kattintva járműve az\nellenőrzési folyamat idejére adatkapcsolatot létesít.", it_IT="Verifichi il Suo utente myAudi per utilizzare questa funzione. I dati mobili devono\nessere attivati. Toccando \"Verifica\" la vettura stabilirà un collegamento dati per la\ndurata del processo di verifica.", nl_NL="Verifieer je myAudi-gebruiker om deze functie te gebruiken. Hiervoor moeten\nmobiele data zijn geactiveerd. Als je op \"Verifiëren\" tikt, zal je auto een\ndataverbinding voor de duur van het verificatieproces opbouwen.", no_NO="Du må verifisere myAudi-brukeren din for å bruke denne funksjonen. Det krever at\nmobildata er aktivert. Når du trykker på Verifiser, oppretter bilen dataforbindelse\nmens verifiseringen skjer.", pl_PL="Aby korzystać z tej funkcji, zweryfikuj konto użytkownika myAudi. W tym celu\ntrzeba aktywować transmisję danych w sieci komórkowej. Po kliknięciu przycisku\n„Weryfikuj” pojazd nawiąże połączenie danych na czas trwania procesu weryfikacji.", pt_PT="Por favor, valida o teu utilizador myAudi para poderes utilizar esta função. Para isso,\nos dados móveis têm de estar ativos. Quando tocas em \"Validar\" o teu veículo\nestabelece uma ligação de dados durante o período em que decorre o processo de\nvalidação.", ro_RO="Verificaţi utilizatorul myAudi, pentru a utiliza această funcţie. În acest scop trebuie\nsă fie activate datele mobile. Dacă apăsaţi pe \"Verificare\", autovehiculul va iniţia o\nconexiune de date pe durata procesului de verificare.", ru_RU="Подтвердите своего пользователя myAudi, чтобы использовать эту функцию.\nДля этого необходимо включить мобильные данные. При нажатии на\n«Подтвердить» ваш автомобиль установит соединение для передачи данных на\nвремя процесса подтверждения.", sk_SK="Overte svojho používateľa myAudi, aby ste mohli používať túto funkciu. Mobilné\ndáta musia byť na to aktivované. Keď kliknete na „Overiť“, vaše vozidlo vytvorí\ndátové pripojenie na dobu overovacieho procesu.", sl_SI="Za uporabo te funkcije preverite pristnost uporabnika myAudi. Mobilni podatki\nmorajo biti za to aktivirani. Ko pritisnete na \"Preverjanje pristnosti\", vaše vozilo za\nčas trajanja preverjanja pristnosti vzpostavi podatkovno povezavo.", sr_RS="Izvršite verifikaciju Vašeg myAudi korisnika da koristite ovu funkciju. U tu svrhu\nmoraju da budu aktivirani mobilni podaci. Kada dodirnete na „Verifikovati”, Vaše\nvozilo uspostavlja vezu sa podacima tokom trajanja procesa verifikacije.", sv_SE="Verifiera din myAudi-användare för att använda den här funktionen. Mobildata\nmåste vara aktiverade. När du trycker på ”Verifiera” upprättar bilen en\ndataanslutning under tiden verifieringsprocessen pågår.", tr_TR="Bu fonksiyonu kullanmak için, kullanıcını doğrula. Bunun için mobil veriler\netkinleştirilmiş olmalıdır. \"Doğrula\" üzerine dokunduğunda, aracın doğrulama\nişlemi süresince bir veri bağlantısı kuracaktır.", uk_UA="Щоб скористатися цією функцією, підтвердьте свій профіль користувача myAudi.\nДля цього необхідно активувати мобільні дані. Коли ви натиснете\n«Підтвердити», ваш автомобіль встановить з'єднання для передачі даних на час\nпроцесу підтвердження.")
texttool_globals_dialog_message___token_missing_temporary_user_max_user_dialog_message = TextObject(bs_BA="Ova funkcija nije raspoloživa za inkognito korisnika. Prijavite se preko vašeg myAudi\nnaloga kako biste mogli koristiti funkciju.", cs_CZ="Tato funkce není k dispozici pro anonymního uživatele. Chcete-li tuto funkci\npoužívat, přihlaste se pomocí svého účtu myAudi.", da_DK="Denne funktion er ikke tilgængelig for inkognitobrugeren. Log på med din\nmyAudi-konto for at kunne anvende funktionen.", de_DE="Diese Funktion ist für den Inkognito-Nutzer nicht verfügbar. Bitte melde dich mit\ndeinem myAudi Account an, um die Funktion nutzen zu können.", el_GR="Αυτή η λειτουργία δεν είναι διαθέσιμη για τον ανώνυμο (incognito) χρήστη.\nΣυνδεθείτε (log in) με τον λογαριασμό myAudi σας, για να μπορέσετε να\nχρησιμοποιήσετε αυτήν τη λειτουργία.", en_GB="This function is not available for temporary users. Please log in with your myAudi\naccount to use the function.", es_ES="Esta función no está disponible para el usuario incógnito. Inicie sesión con su\ncuenta myAudi para poder utilizar la función.", fi_FI="Toiminto ei ole tilapäiskäyttäjän käytettävissä. Kirjaudu myAudi-käyttäjätilillesi\nkäyttääksesi toimintoa.", fr_FR="Cette fonction n'est pas disponible pour le profil utilisateur incognito. Veuillez vous\nconnecter à votre compte myAudi pour pouvoir utiliser la fonction.", hr_HR="Ova funkcija nije raspoloživa za inkognito korisnike. Prijavite se svojim myAudi\nkorisničkim računom kako biste koristili funkciju.", hu_HU="Ez a funkció az inkognitó felhasználó számára nem érhető el. Jelentkezz be myAudi\nfiókoddal, hogy használni tudd a funkciót.", it_IT="Questa funzione non è disponibile per gli utenti in incognito. Effettuare il login con\nil proprio account myAudi per poter utilizzare la funzione.", nl_NL="Deze functie is niet beschikbaar voor de incognito-gebruiker. Meld je aan met je\nmyAudi-account om de functie te kunnen gebruiken.", no_NO="Denne funksjonen er ikke tilgjengelig for inkognito-brukeren. Du må logge på med\nmyAudi-kontoen din for å kunne bruke funksjonen.", pl_PL="Ta funkcja nie jest dostępna dla użytkownika incognito. Aby korzystać z tej funkcji,\nzaloguj się z użyciem swojego konta myAudi.", pt_PT="Esta função não está disponível para o utilizador anónimo. Por favor, faz login com\na tua conta myAudi para poderes utilizar a função.", ro_RO="Această funcţie este indisponibilă pentru utilizatorul incognito. Autentificaţi-vă cu\ncontul dumneavoastră myAudi, pentru a putea utiliza funcţia.", ru_RU="Эта функция недоступна для пользователей инкогнито. Пожалуйста, войдите в\nсвою учетную запись myAudi, чтобы воспользоваться этой функцией.", sk_SK="Táto funkcia nie je k dispozícii pre Inkognito používateľa. Prosím, prihláste sa\npomocou svojho účtu myAudi, aby ste mohli túto funkciu používať.", sl_SI="Ta funkcija ni na voljo za inkognito uporabnika. Za uporabo funkcije se prijavite s\nsvojim računom myAudi.", sr_RS="Ova funkcija nije dostupna za inkognito  korisnika. Prijavite se preko Vašeg myAudi\nnaloga da biste mogli koristiti funkciju.", sv_SE="Den här funktionen är inte tillgänglig för Inkognito-användaren. Logga in med ditt\nmyAudi-konto för att använda funktionen.", tr_TR="Bu fonksiyon gizli kullanıcı için mevcut değildir. Fonksiyonu kullanabilmek için,\nlütfen myAudi hesabınla oturum aç.", uk_UA="Ця функція недоступна для користувачів інкогніто. Будь ласка, увійдіть у свій\nобліковий запис myAudi, щоб скористатися цією функцією.")
texttool_globals_dialog_message___token_missing_temporary_user_warning = TextObject(bs_BA="Ova funkcija nije raspoloživa za inkognito korisnika. Prijavite se preko vašeg myAudi\nnaloga kako biste mogli koristiti funkciju.", cs_CZ="Tato funkce není k dispozici pro anonymního uživatele. Chcete-li tuto funkci\npoužívat, přihlaste se pomocí svého účtu myAudi.", da_DK="Denne funktion er ikke tilgængelig for inkognitobrugeren. Log på med din\nmyAudi-konto for at kunne anvende funktionen.", de_DE="Diese Funktion ist für den Inkognito-Nutzer nicht verfügbar. Bitte melde dich mit\ndeinem myAudi Account an, um die Funktion nutzen zu können.", el_GR="Αυτή η λειτουργία δεν είναι διαθέσιμη για τον ανώνυμο (incognito) χρήστη.\nΣυνδεθείτε (log in) με τον λογαριασμό myAudi σας, για να μπορέσετε να\nχρησιμοποιήσετε αυτήν τη λειτουργία.", en_GB="This function is not available for temporary users. Please log in with your myAudi\naccount to use the function.", es_ES="Esta función no está disponible para el usuario incógnito. Inicie sesión con su\ncuenta myAudi para poder utilizar la función.", fi_FI="Toiminto ei ole tilapäiskäyttäjän käytettävissä. Kirjaudu myAudi-käyttäjätilillesi\nkäyttääksesi toimintoa.", fr_FR="Cette fonction n'est pas disponible pour le profil utilisateur incognito. Veuillez vous\nconnecter à votre compte myAudi pour pouvoir utiliser la fonction.", hr_HR="Ova funkcija nije raspoloživa za inkognito korisnike. Prijavite se svojim myAudi\nkorisničkim računom kako biste koristili funkciju.", hu_HU="Ez a funkció az inkognitó felhasználó számára nem érhető el. Jelentkezz be myAudi\nfiókoddal, hogy használni tudd a funkciót.", it_IT="Questa funzione non è disponibile per gli utenti in incognito. Effettuare il login con\nil proprio account myAudi per poter utilizzare la funzione.", nl_NL="Deze functie is niet beschikbaar voor de incognito-gebruiker. Meld je aan met je\nmyAudi-account om de functie te kunnen gebruiken.", no_NO="Denne funksjonen er ikke tilgjengelig for inkognito-brukeren. Du må logge på med\nmyAudi-kontoen din for å kunne bruke funksjonen.", pl_PL="Ta funkcja nie jest dostępna dla użytkownika incognito. Aby korzystać z tej funkcji,\nzaloguj się z użyciem swojego konta myAudi.", pt_PT="Esta função não está disponível para o utilizador anónimo. Por favor, faz login com\na tua conta myAudi para poderes utilizar a função.", ro_RO="Această funcţie este indisponibilă pentru utilizatorul incognito. Autentificaţi-vă cu\ncontul dumneavoastră myAudi, pentru a putea utiliza funcţia.", ru_RU="Эта функция недоступна для пользователей инкогнито. Пожалуйста, войдите в\nсвою учетную запись myAudi, чтобы воспользоваться этой функцией.", sk_SK="Táto funkcia nie je k dispozícii pre Inkognito používateľa. Prosím, prihláste sa\npomocou svojho účtu myAudi, aby ste mohli túto funkciu používať.", sl_SI="Ta funkcija ni na voljo za inkognito uporabnika. Za uporabo funkcije se prijavite s\nsvojim računom myAudi.", sr_RS="Ova funkcija nije dostupna za inkognito  korisnika. Prijavite se preko Vašeg myAudi\nnaloga da biste mogli koristiti funkciju.", sv_SE="Den här funktionen är inte tillgänglig för Inkognito-användaren. Logga in med ditt\nmyAudi-konto för att använda funktionen.", tr_TR="Bu fonksiyon gizli kullanıcı için mevcut değildir. Fonksiyonu kullanabilmek için,\nlütfen myAudi hesabınla oturum aç.", uk_UA="Ця функція недоступна для користувачів інкогніто. Будь ласка, увійдіть у свій\nобліковий запис myAudi, щоб скористатися цією функцією.")
texttool_globals_dialog_message___user_data_sync_waiting_warning = TextObject(bs_BA="Individualne postavke Vašeg myAudi korisnika su aktualizirane. Želite li da ih\npreuzmete u vozilo?", cs_CZ="Individuální nastavení Vašeho uživatele myAudi byla aktualizována. Chcete je převzít\ndo vozidla?", da_DK="Din myAudi-brugers individuelle indstillinger blev opdateret. Vil du overføre dem til\nbilen?", de_DE="Die individuellen Einstellungen deines myAudi Nutzers wurden aktualisiert.\nMöchtest du diese ins Fahrzeug übernehmen?", el_GR="Έγινε ενημέρωση των επιμέρους ρυθμίσεων του λογαριασμού σας χρήστη myAudi.\nΘέλετε να τις υιοθετήσετε στο όχημα;", en_GB="The individual settings for your myAudi user have been updated. Would you like to\napply these in the vehicle?", es_ES="Los ajustes individuales de su usuario myAudi se han actualizado. ¿Desea aplicarlos\nen el vehículo?", fi_FI="myAudi-käyttäjän yksilölliset asetukset on päivitetty. Haluatko ottaa ne käyttöön\nautossa?", fr_FR="Les réglages personnels de votre profil utilisateur myAudi ont été actualisés.\nSouhaitez-vous les reprendre dans le véhicule?", hr_HR="Individualne postavke vašeg myAudi korisnika su aktualizirane. Želite li ih preuzeti u\nvozilo?", hu_HU="A myAudi felhasználód egyedi beállításai frissítésre kerültek. Át szeretnéd venni\nezeket a járműbe?", it_IT="Le impostazioni individuali dell'utente myAudi sono state aggiornate. Acquisirle\nsulla vettura?", nl_NL="De individuele instellingen van je myAudi gebruiker zijn bijgewerkt. Wil je ze\novernemen in het voertuig?", no_NO="De personlige innstillingene til myAudi-brukeren din er oppdatert. Vil du bruke dem\ni bilen?", pl_PL="Indywidualne ustawienia Twojego użytkownika myAudi zostały zaktualizowane. Czy\nchcesz, by zostały zastosowane w pojeździe?", pt_PT="Os ajustes individuais do teu utilizador myAudi foram atualizados. Desejas\nassumi-los no veículo?", ro_RO="Setările individuale ale utilizatorului myAudi au fost actualizate. Doriţi să le preluaţi\nîn autovehicul?", ru_RU="Индивидуальные настройки Вашего пользователя myAudi обновлены. Хотите\nприменить их в автомобиле?", sk_SK="Individuálne nastavenia vášho používateľa myAudi sa aktualizovali. Chcete ich\nprebrať do vozidla?", sl_SI="Individualne nastavitve uporabnika myAudi so bile posodobljene. Ali jih želite\nprevzeti v vozilo?", sr_RS="Individualna podešavanja vašeg myAudi korisnika su ažurirana. Da li ih želite\npreuzeti u vozilo?", sv_SE="De individuella inställningarna för din myAudi-användare har uppdaterats. Vill du\növerföra dem till fordonet?", tr_TR="myAudi kullanıcının kişisel ayarları güncellendi. Bunları araca devralmak ister\nmisin?", uk_UA="Індивідуальні настройки користувача myAudi оновлені. Хочете застосувати їх в\nавтомобілі?")
texttool_globals_dialog_message___user_data_sync_with_atne_waiting_warning = TextObject(bs_BA="Individualne postavke vašeg myAudi korisnika su aktualizirane. Želite li ih preuzeti u\nvozilo? To može uticati na aktivne postavke sistema za pomoć vozaču, sjedišta,\nupravljača i bočnih ogledala.", cs_CZ="Byla aktualizována individuální nastavení vašeho uživatele myAudi. Chcete je\npřenést do vozidla? To může mít vliv na nastavení aktivního asistenčního systému\nřidiče, nastavení sedadel, volantu a bočních zpětných zrcátek.", da_DK="Din myAudi-brugers individuelle indstillinger blev opdateret. Vil du overføre dem til\nbilen? Dette kan påvirke de aktive førerassistentsystemindstillinger, sæde-, rat- og\nsidespejlsindstillinger.", de_DE="Die individuellen Einstellungen deines myAudi Nutzers wurden aktualisiert.\nMöchtest du diese ins Fahrzeug übernehmen? Dies kann Auswirkungen auf aktive\nFahrerassistenzsystemeinstellungen, Sitz-, Lenkrad- und\nSeitenspiegeleinstellungen haben.", el_GR="Ενημερώθηκαν οι επιμέρους ρυθμίσεις του λογαριασμού χρήστη σας myAudi. Θέλατε\nνα τις μεταφέρετε στο όχημα; Αυτό μπορεί να επηρεάσει ενεργές ρυθμίσεις\nσυστημάτων υποβοήθησης οδηγού, ρυθμίσεις καθισμάτων, τιμονιού και πλευρικών\nκαθρεφτών.", en_GB="Your custom myAudi user settings have been updated. Do you want to send these\nto the vehicle? This could affect active driver assist settings, as well as  seat,\nsteering wheel and side mirror settings.", es_ES="Los ajustes personalizados de su usuario myAudi se han actualizado. ¿Desea\naplicarlos en el vehículo? Esto puede afectar a los ajustes que estén activos en los\nsistemas de asistencia al conductor y a los ajustes del asiento, del volante y de los\nretrovisores laterales.", fi_FI="myAudi-käyttäjän yksilölliset asetukset on päivitetty. Haluatko ottaa ne käyttöön\nautossa? Tämä voi vaikuttaa aktiivisten kuljettajaa avustavien järjestelmien\njärjestelmäasetuksiin, istuin-, ohjauspyörä- ja sivupeiliasetuksiin.", fr_FR="Les réglages personnels de votre profil utilisateur myAudi ont été actualisés.\nSouhaitez-vous les reprendre dans le véhicule? Cela peut avoir une influence sur les\nréglages des systèmes d'assistance du conducteur activés ainsi que sur les réglages\ndes sièges, du volant et des rétroviseurs extérieurs.", hr_HR="Individualne postavke vašeg myAudi korisničkog računa su aktualizirane. Želite li ih\npreuzeti u vozilo? To može imati posljedice po aktivne postavke sustava potpora za\nvozača, sjedala, kola upravljača i bočnih zrcala.", hu_HU="A myAudi felhasználód egyedi beállításai frissítésre kerültek. Át szeretnéd venni\nezeket a járműbe? Ez befolyásolhatja a vezetőtámogató rendszerek aktív\nbeállításait, valamint az ülés, a kormánykerék és az oldalsó tükrök beállításait.", it_IT="Le impostazioni individuali dell'utente myAudi sono state aggiornate. Acquisirle\nsulla vettura? Ciò può influire sulle impostazioni dei sistemi di assistenza alla guida\nattivi, dei sedili, del volante e degli specchi retrovisori.", nl_NL="De individuele instellingen van je myAudi gebruiker zijn geactualiseerd. Wil je deze\nin het voertuig overnemen? Dit kan gevolgen voor de actieve instellingen van het\nbestuurdershulpsysteem, stoel, stuur en zijspiegels hebben.", no_NO="De personlige innstillingene til myAudi-brukeren din er oppdatert. Vil du bruke dem\ni bilen? Innstillinger for førerassistentsystemer, sete, ratt og sidespeil kan bli\nendret.", pl_PL="Indywidualne ustawienia Twojego użytkownika myAudi zostały zaktualizowane. Czy\nchcesz, by zostały zastosowane w pojeździe? Może to mieć wpływ na ustawienia\naktywnego systemu wspomagania kierowcy, ustawienia siedzenia, kierownicy i\nlusterek bocznych.", pt_PT="Os ajustes individuais do teu utilizador myAudi foram atualizados. Queres\nassumi-los no veículo? Isto pode ter consequências nos ajustes dos sistemas de\nassistência à condução, nos ajustes dos bancos, do volante e nos ajustes dos\nespelhos laterais.", ro_RO="Setările individuale ale utilizatorului myAudi au fost actualizate. Doriţi să le preluaţi\nîn autovehicul? Aceasta poate avea efecte asupra setărilor active ale sistemelor de\nasistenţă a şoferului, ale scaunului, volanului şi oglinzilor laterale.", ru_RU="Индивидуальные настройки вашего пользователя myAudi были обновлены.\nХотите перенести их в автомобиль? Это может повлиять на настройки активных\nассистирующих систем, настройки сидений, рулевого колеса и боковых зеркал.", sk_SK="Individuálne nastavenia vášho používateľa myAudi boli aktualizované. Chcete tieto\nprevziať do vozidla? Môže to ovplyvniť nastavenia aktívneho podporného systému\nvodiča, nastavenia sedadla, volantu a bočných zrkadiel.", sl_SI="Individualne nastavitve uporabnika myAudi so bile posodobljene. Ali jih želite\nprevzeti v vozilo? To lahko vpliva na aktivne nastavitve asistenčnih sistemov ter\nnastavitve sedežev, volana in stranskih ogledal.", sr_RS="Individualna podešavanja vašeg myAudi korisnika su ažurirana. Da li želite da ih\npreuzmete u vozilo? To može da utiče na aktivna podešavanja sistema za asistenciju\nvozaču, sedišta, upravljača i bočnih ogledala.", sv_SE="De individuella inställningarna för din myAudi-användare har uppdaterats. Vill du\növerföra dem till fordonet? Detta kan påverka aktiva inställningar för\nförarassistanssystemen, sätena, ratten och ytterbackspeglarna.", tr_TR="myAudi kullanıcının kişisel ayarları güncellendi. Bunları araca devralmak ister\nmisin? Bu, aktif sürücü destek sistemi ayarlarına, koltuk, direksiyon simidi ve yan\nayna ayarlarına etki edebilir.", uk_UA="Індивідуальні налаштування вашого користувача myAudi було оновлено.\nБажаєте перенести їх до автомобіля? Це може вплинути на налаштування\nактивних допоміжних систем, налаштування сидінь, керма та бічних дзеркал.")
texttool_globals_dialog_message___wbl_generic_error_message = TextObject(bs_BA="Dodavanje novog korisnika nije bilo uspješno. Pokušajte ponovo kasnije.", cs_CZ="Přidání uživatele nebylo úspěšné. Zkuste to prosím později.", da_DK="Tilføjelse af bruger blev ikke gennemført korrekt. Forsøg igen senere.", de_DE="Das Hinzufügen des Nutzers war nicht erfolgreich. Bitte versuche es zu einem\nspäteren Zeitpunkt erneut.", el_GR="Η προσθήκη του χρήστη δεν ήταν επιτυχής. Προσπαθήστε πάλι αργότερα.", en_GB="Unable to add the user. Please try again later.", es_ES="El usuario no se ha podido añadir. Por favor, vuelva a intentarlo más tarde.", fi_FI="Käyttäjän lisääminen epäonnistui. Yritä myöhemmin uudelleen.", fr_FR="L'utilisateur n'a pas pu être ajouté. Veuillez réessayer ultérieurement.", hr_HR="Dodavanje korisnika nije bilo uspješno. Pokušajte ponovno kasnije.", hu_HU="A felhasználó hozzáadása sikertelen volt. Kérünk, próbáld újra később.", it_IT="Non è stato possibile aggiungere l'utente. Si prega di riprovare più tardi.", nl_NL="Het toevoegen van de gebruiker is niet gelukt. Probeer het op een later moment\nnog eens.", no_NO="Kan ikke legge til brukeren. Prøv igjen senere.", pl_PL="Dodawanie użytkownika nie powiodło się. Proszę spróbować ponownie później.", pt_PT="A introdução de um novo utilizador não foi bem sucedida. Por favor, volta a tentar\nmais tarde.", ro_RO="Adăugarea utilizatorului a eşuat. Reîncercaţi mai târziu.", ru_RU="Не удалось добавить пользователя. Пожалуйста, повторите попытку позже.", sk_SK="Pridanie používateľa nebolo úspešné. Prosím, pokúste sa o to znovu neskôr.", sl_SI="Dodajanje uporabnika ni bilo uspešno. Poskusite znova pozneje.", sr_RS="Dodavanje korisnika je bilo neuspešno. Pokušajte ponovo kasnije.", sv_SE="Det gick inte att lägga till användaren. Försök igen senare.", tr_TR="Kullanıcının eklenmesi başarısız oldu. Lütfen daha sonra yeniden dene.", uk_UA="Не вдалося додати користувача. Будь ласка, спробуйте пізніше.")
texttool_globals_dialog_message___wbl_profile_assigned_other_user_dialog_text = TextObject(bs_BA="Korisnik %1 već postoji na popisu korisnika. Želite li sada\npreći na ovog korisnika?", cs_CZ="Uživatel %1 již existuje v seznamu uživatelů. Chcete se nyní\npřepnout na tohoto uživatele?", da_DK="Brugeren %1 eksisterer allerede på brugerlisten. Vil du\nskifte til denne bruger nu?", de_DE="Der Nutzer %1 existiert bereits in der Nutzerliste.\nMöchtest du jetzt zu diesem Nutzer wechseln?", el_GR="Ο χρήστης %1 υπάρχει ήδη στη λίστα χρηστών. Θέλετε να\nαλλάξετε τώρα σε αυτόν τον χρήστη;", en_GB="User %1 is already in the user list. Would you like to switch\nto this user now?", es_ES="El usuario %1 ya existe en la lista de usuarios. ¿Desea\ncambiar ahora a dicho usuario?", fi_FI="Käyttäjä %1 on jo käyttäjäluettelossa. Haluatko vaihtaa\ntähän käyttäjään nyt?", fr_FR="Le profil utilisateur %1 existe déjà dans la liste des profils.\nSouhaitez-vous accéder maintenant à ce profil utilisateur?", hr_HR="Korisnik %1 već postoji u popisu korisnika. Želite li se sada\nprebaciti na tog korisnika?", hu_HU="%1 felhasználó már létezik a felhasználólistán. Át\nszeretnél most váltani erre a felhasználóra?", it_IT="L'utente %1 esiste già nella lista utenti. Si desidera\npassare adesso a questo utente?", nl_NL="De gebruiker %1 komt al voor in de gebruikerlijst. Wil je nu\nnaar deze gebruiker overschakelen?", no_NO="Brukeren %1 finnes allerede i brukerlisten. Vil du bytte til\ndenne brukeren nå?", pl_PL="Użytkownik %1 już istnieje na liście użytkowników. Czy\nchcesz teraz przełączyć się na tego użytkownika?", pt_PT="O utilizador %1 já existe na lista de utilizadores. Queres\nmudar agora para este utilizador?", ro_RO="Utilizatorul %1 există deja în lista de utilizatori. Doriţi să\ncomutaţi acum la acest utilizator?", ru_RU="Пользователь %1 уже существует в списке\nпользователей. Хотите переключиться на этого пользователя сейчас?", sk_SK="Používateľ %1 už v zozname používateľov existuje. Chcete\nteraz zmeniť na tohto používateľa?", sl_SI="Uporabnik %1 že obstaja na seznamu uporabnikov. Ali\nželite zdaj preklopiti na tega uporabnika?", sr_RS="Korisnik %1 već postoji na listi korisnika. Da li sada želite\nda prebacite na ovog korisnika?", sv_SE="Användaren %1 finns redan i användarlistan. Vill du byta\ntill användaren nu?", tr_TR="Kullanıcı %1 zaten kullanıcı listesinde mevcut. Şimdi bu\nkullanıcıya geçmek ister misin?", uk_UA="Користувач %1 уже існує у списку користувачів. Хочете\nпереключитися на цього користувача зараз?")
texttool_globals_dialog_message_with_decorator___guest_welcome__possible_remote_access = TextObject(bs_BA="Ovlaštenja za daljinski pristup su dodijeljena.", cs_CZ="Jsou přiřazena oprávnění ke vzdálenému přístupu.", da_DK="Fjernadgangstilladelser tildelt.", de_DE="Fernzugriffsberechtigungen sind vergeben.", el_GR="Έχουν χορηγηθεί δικαιώματα απομακρυσμένης πρόσβασης.", en_GB="Remote access rights assigned.", es_ES="Los permisos de acceso remoto están asignados.", fi_FI="Etäkäyttöoikeudet on myönnetty.", fr_FR="Des autorisations d'accès à distance sont attribuées.", hr_HR="Dodijeljena su ovlaštenja za daljinski pristup.", hu_HU="Távoli hozzáférési jogok megadva.", it_IT="Sono presenti diritti di accesso remoto.", nl_NL="Autorisaties bediening op afstand verleend.", no_NO="Det er gitt fjerntilgangsrettigheter.", pl_PL="Uprawnienia dostępu zdalnego zostały udzielone.", pt_PT="Permissões de acesso remoto estão concedidas.", ro_RO="Drepturile de acces de la distanţă sunt alocate.", ru_RU="Права на дистанционный доступ присвоены.", sk_SK="Oprávnenia na vzdialený prístup sú priradené.", sl_SI="Pooblastila za oddaljeni dostop so dodeljena.", sr_RS="Ovlašćenja za daljinski pristup su dodeljena.", sv_SE="Fjärråtkomstbehörigheter har tilldelats.", tr_TR="Uzaktan erişim izinleri atanmıştır.", uk_UA="Права на віддалений доступ присвоєно.")
texttool_globals_dialog_message_with_decorator___guest_welcome__primary_user = TextObject(bs_BA="Glavni korisnik je: %1 %2", cs_CZ="Hlavní uživatel je: %1 %2", da_DK="Den primære bruger er: %1 %2.", de_DE="Der Hauptnutzer ist: %1 %2", el_GR="Ο/Η βασικός/-ή χρήστης είναι ο/η: %1\n%2", en_GB="The key user is: %1 %2", es_ES="El usuario principal es: %1 %2", fi_FI="Pääkäyttäjä on: %1 %2", fr_FR="L'utilisateur principal est: %1\n%2", hr_HR="Glavni korisnik je: %1 %2", hu_HU="A főfelhasználó: %1 %2", it_IT="L'utente principale è: %1 %2", nl_NL="De hoofdgebruiker is: %1 %2", no_NO="Hovedbrukeren er: %1 %2", pl_PL="Użytkownikiem głównym jest: %1\n%2", pt_PT="O utilizador principal é: %1 %2", ro_RO="Utilizatorul principal este: %1\n%2", ru_RU="Основным пользователем является: %1\n%2", sk_SK="Hlavný používateľ je: %1 %2", sl_SI="Glavni uporabnik je: %1 %2", sr_RS="Glavni korisnik je: %1 %2", sv_SE="Huvudanvändaren är: %1 %2", tr_TR="Ana kullanıcı %1 %2 kişisidir", uk_UA="Основним користувачем є: %1\n%2")
texttool_globals_edit_text_error___add_online_user_error_wrong_credentials = TextObject(bs_BA="Pogrešna adresa e-pošte ili lozinka", cs_CZ="E-mailová adresa nebo heslo chybné", da_DK="E-mailadresse eller password er forkert.", de_DE="E-Mail-Adresse oder Passwort ist falsch", el_GR="Η διεύθυνση email ή ο κωδικός πρόσβασης είναι λάθος", en_GB="Incorrect e-mail address or password", es_ES="E-mail o contraseña incorrectos", fi_FI="Sähköpostiosoite tai salasana on väärä", fr_FR="L'adresse e-mail ou le mot de passe est incorrect", hr_HR="E-mail adresa ili lozinka je pogrešna", hu_HU="Az e-mail-cím vagy a jelszó helytelen", it_IT="Indirizzo e-mail o password errati", nl_NL="E-mailadres of wachtwoord is fout", no_NO="Feil e-postadresse eller passord", pl_PL="Adres e-mail lub hasło są nieprawidłowe", pt_PT="O endereço de e-mail ou a palavra-passe está incorreto", ro_RO="Adresa de e-mail sau parole este incorectă", ru_RU="Адрес электронной почты или пароль неправильный", sk_SK="E-Mail-adresa alebo heslo sú neprávne", sl_SI="Napačen elektronski naslov ali geslo", sr_RS="Adresa e-pošte ili lozinka su pogrešni", sv_SE="E-postadressen eller lösenordet är felaktigt", tr_TR="E-posta adresi veya şifre yanlış", uk_UA="Адреса електронної пошти або пароль неправильний")
texttool_globals_edit_text_error___confirm_spin_check_error_blocked_a_minute = TextObject(bs_BA="PIN je previše često pogrešno unesen. Unos PIN-a je sada\nblokiran na 1 min.", cs_CZ="Zadali jste příliš mnohokrát chybný PIN. Zadávání PINu je\nnyní zablokováno na 1 min.", da_DK="Pinkode blev angivet forkert for mange gange.\nPinkodeangivelse er nu spærret i 1 min.", de_DE="Die PIN wurde zu oft falsch eingegeben. Die PIN-Eingabe\nist nun für 1 min gesperrt.", el_GR="Το PIN καταχωρίστηκε λανθασμένα πολύ συχνά. Η\nκαταχώριση του PIN θα φραγεί τώρα για 1 λεπτό.", en_GB="You have entered an incorrect PIN too many times. PIN\nentry is now locked for 1 min.", es_ES="Ha introducido un PIN incorrecto demasiadas veces. El\nPIN no se puede introducir durante 1 min.", fi_FI="PIN-koodi on syötetty väärin liian monta kertaa.\nPIN-koodin syöttäminen on nyt lukittu minuutin ajaksi.", fr_FR="Vous avez entré trop souvent un code PIN erroné. La\nsaisie du code PIN est désormais bloquée pendant 1\nminute.", hr_HR="PIN je prečesto unesen pogrešno. Unos PIN-a blokiran je\nna 1 min.", hu_HU="A PIN-kódot túl sok alkalommal hibásan adták meg. A\nPIN-kód bevitele most 1 percre le van tiltva.", it_IT="È stato immesso un PIN errato troppe volte. Ora\nl'immissione PIN è bloccata per 1 min.", nl_NL="Te vaak verkeerde pincode ingevoerd. Invoer pincode 1\nminuut geblokkeerd.", no_NO="Du har lagt inn feil PIN for mange ganger. Inntasting av\nPIN er sperret i 1 minutt.", pl_PL="Zbyt często wprowadzano nieprawidłowy kod PIN.\nWprowadzanie kodu PIN zostało teraz zablokowane na 1\nmin.", pt_PT="O PIN incorreto foi introduzido demasiadas vezes. A\nintrodução do PIN está bloqueada durante 1 minuto.", ro_RO="Codul PIN a fost introdus eronat prea des. Introducerea\ncodului PIN este blocată acum pentru 1 min.", ru_RU="PIN был введен неправильно слишком много раз. Ввод\nPIN теперь заблокирован на 1 мин.", sk_SK="PIN kód bol zadaný príliš často nesprávne. Zadanie PIN je\nteraz zablokované na 1 min.", sl_SI="Prevečkrat je bila vnešena napačna PIN-koda. Vnos\nPIN-kode je zdaj 1 min. blokiran.", sr_RS="PIN je suviše često pogrešno unesen. Unos PIN-a je sada\nblokiran na 1 min.", sv_SE="Du har angett fel PIN-kod för många gånger.\nPIN-kodsinmatning är spärrad i 1 minut.", tr_TR="PIN kodu çok sık yanlış girildi. PIN girişi şimdi 1 dakika\niçin kilitlenmiştir.", uk_UA="PIN-код було введено неправильно надто багато разів.\nВведення PIN-коду заблоковано на 1 хв.")
texttool_globals_edit_text_error___confirm_spin_check_error_blocked_an_hour = TextObject(bs_BA="PIN je previše često pogrešno unesen. Unos PIN-a je sada\nblokiran na 1 h.", cs_CZ="Zadali jste příliš mnohokrát chybný PIN. Zadávání PINu je\nnyní zablokováno na 1 hod.", da_DK="Pinkode blev angivet forkert for mange gange.\nPinkodeangivelse er nu spærret i 1 h.", de_DE="Die PIN wurde zu oft falsch eingegeben. Die PIN-Eingabe\nist nun für 1 h gesperrt.", el_GR="Το PIN καταχωρίστηκε λανθασμένα πολύ συχνά. Η\nκαταχώριση του PIN θα φραγεί τώρα για 1 ώρα.", en_GB="You have entered an incorrect PIN too many times. PIN\nentry is now locked for 1 hr.", es_ES="Ha introducido un PIN incorrecto demasiadas veces. El\nPIN no se puede introducir durante 1 h.", fi_FI="PIN-koodi on syötetty väärin liian monta kertaa.\nPIN-koodin syöttäminen on nyt lukittu tunnin ajaksi.", fr_FR="Vous avez entré trop souvent un code PIN erroné. La\nsaisie du code PIN est désormais bloquée pendant 1\nheure.", hr_HR="PIN je prečesto unesen pogrešno. Unos PIN-a blokiran je\nna 1 h.", hu_HU="A PIN-kódot túl sok alkalommal hibásan adták meg. A\nPIN-kód bevitele most 1 órára le van tiltva.", it_IT="È stato immesso un PIN errato troppe volte. Ora\nl'immissione PIN è bloccata per 1 h.", nl_NL="Te vaak verkeerde pincode ingevoerd. Invoer pincode is nu\n1 uur geblokkeerd.", no_NO="Du har lagt inn feil PIN for mange ganger. Inntasting av\nPIN er sperret i 1 time.", pl_PL="Zbyt często wprowadzano nieprawidłowy kod PIN.\nWprowadzanie kodu PIN zostało teraz zablokowane na 1\nh.", pt_PT="O PIN incorreto foi introduzido demasiadas vezes. A\nintrodução do PIN está bloqueada durante 1 hora.", ro_RO="Codul PIN a fost introdus eronat prea des. Introducerea\ncodului PIN este blocată acum pentru 1 h.", ru_RU="PIN был введен неправильно слишком много раз. Ввод\nPIN теперь заблокирован на 1 ч.", sk_SK="PIN kód bol zadaný príliš často nesprávne. Zadanie PIN je\nteraz zablokované na 1 h.", sl_SI="Prevečkrat je bila vnešena napačna PIN-koda. Vnos\nPIN-kode je zdaj 1 h blokiran.", sr_RS="PIN je suviše često pogrešno unesen. Unos PIN-a je sada\nblokiran na 1 sat.", sv_SE="Du har angett fel PIN-kod för många gånger.\nPIN-kodsinmatning är spärrad i 1 timme.", tr_TR="PIN kodu çok sık yanlış girildi. PIN girişi şimdi 1 saat için\nkilitlenmiştir.", uk_UA="PIN-код було введено неправильно надто багато разів.\nВведення PIN-коду заблоковано на 1 год.")
