texttool_globals_toast___accout_federation_not_available_error = TextObject(bs_BA="Došlo je do tehničke greške. Pokušajte ponovo kasnije.", cs_CZ="Vyskytla se technická chyba. Zkuste to prosím znovu později.", da_DK="Teknisk fejl opstået. Forsøg igen senere.", de_DE="Es ist ein technischer Fehler aufgetreten. Bitte versuche es\nspäter erneut.", el_GR="Προέκυψε τεχνικό σφάλμα. Προσπαθήστε πάλι αργότερα.", en_GB="A technical error has occurred. Please try again later.", es_ES="Se ha producido un error técnico. Por favor, inténtelo de nuevo\nmás tarde.", fi_FI="Tekninen virhe. Yritä myöhemmin uudelleen.", fr_FR="Une erreur technique s'est produite. Veuillez réessayer\nultérieurement.", hr_HR="Nastupila je tehnička greška. Pokušajte ponovno kasnije.", hu_HU="Technikai hiba lépett fel. Próbáld újra később.", it_IT="Si è verificato un errore tecnico. Si prega di riprovare più tardi.", nl_NL="Er is een technische fout opgetreden. Probeer het later opnieuw.", no_NO="Det har oppstått en teknisk feil. Prøv på nytt senere.", pl_PL="Wystąpił błąd techniczny. Proszę spróbować ponownie później.", pt_PT="Ocorreu uma falha técnica. Por favor, volta a tentar mais tarde.", ro_RO="A apărut o eroare tehnică. Reîncercaţi mai târziu.", ru_RU="Возникла техническая ошибка. Повторите попытку позже.", sk_SK="Vyskytla sa technická chyba. Prosím, pokúste sa o to znovu\nneskôr.", sl_SI="Prišlo je do tehnične napake. Poskusite znova pozneje.", sr_RS="Došlo je do tehničke greške. Pokušajte ponovo kasnije.", sv_SE="Ett tekniskt fel har uppstått. Försök igen senare.", tr_TR="Teknik bir hata oluştu. Lütfen daha sonra yeniden dene.", uk_UA="Сталася технічна помилка. Спробуйте пізніше.")
texttool_globals_toast___add_offline_user_error_already_exists = TextObject(bs_BA="Korisnik već postoji na listi korisnika.", cs_CZ="Uživatel již existuje v seznamu uživatelů.", da_DK="Bruger findes allerede på brugerliste.", de_DE="Der Nutzer ist bereits in der Nutzerliste vorhanden.", el_GR="Ο χρήστης υπάρχει ήδη στη λίστα χρηστών.", en_GB="The user is already in the user list.", es_ES="El usuario ya consta en la lista de usuarios.", fi_FI="Käyttäjä on jo käyttäjälistalla.", fr_FR="L'utilisateur est déjà présent dans la liste des utilisateurs.", hr_HR="Korisnik već postoji u popisu korisnika.", hu_HU="A felhasználó már létezik a felhasználói listán.", it_IT="L'utente è già presente nella lista utenti.", nl_NL="De gebruiker staat al in de gebruikerslijst.", no_NO="Brukeren finnes allerede i brukerlisten.", pl_PL="Użytkownik już jest na liście użytkowników.", pt_PT="O utilizador já consta na lista de utilizadores.", ro_RO="Utilizatorul există deja în lista de utilizatori.", ru_RU="Пользователь уже есть в списке пользователей.", sk_SK="Používateľ už je k dispozícii v zozname používateľov.", sl_SI="Uporabnik je že na seznamu uporabnikov.", sr_RS="Korisnik već postoji na listi korisnika.", sv_SE="Användaren finns redan i användarlistan.", tr_TR="Kullanıcı zaten kullanıcı listesinde mevcut.", uk_UA="Користувач вже є у списку користувачів.")
texttool_globals_toast___add_online_user_error_already_exists = TextObject(bs_BA="Korisnik već postoji na listi korisnika.", cs_CZ="Uživatel již existuje v seznamu uživatelů.", da_DK="Bruger findes allerede på brugerliste.", de_DE="Der Nutzer ist bereits in der Nutzerliste vorhanden.", el_GR="Ο χρήστης υπάρχει ήδη στη λίστα χρηστών.", en_GB="The user is already in the user list.", es_ES="El usuario ya consta en la lista de usuarios.", fi_FI="Käyttäjä on jo käyttäjälistalla.", fr_FR="L'utilisateur est déjà présent dans la liste des utilisateurs.", hr_HR="Korisnik već postoji u popisu korisnika.", hu_HU="A felhasználó már létezik a felhasználói listán.", it_IT="L'utente è già presente nella lista utenti.", nl_NL="De gebruiker staat al in de gebruikerslijst.", no_NO="Brukeren finnes allerede i brukerlisten.", pl_PL="Użytkownik już jest na liście użytkowników.", pt_PT="O utilizador já consta na lista de utilizadores.", ro_RO="Utilizatorul există deja în lista de utilizatori.", ru_RU="Пользователь уже есть в списке пользователей.", sk_SK="Používateľ už je k dispozícii v zozname používateľov.", sl_SI="Uporabnik je že na seznamu uporabnikov.", sr_RS="Korisnik već postoji na listi korisnika.", sv_SE="Användaren finns redan i användarlistan.", tr_TR="Kullanıcı zaten kullanıcı listesinde mevcut.", uk_UA="Користувач вже є у списку користувачів.")
texttool_globals_toast___add_online_user_error_user_without_spin = TextObject(bs_BA="Do sada za Vašeg myAudi korisnika nije dodijeljen myAudi PIN.\nDefinirajte PIN u myAudi aplikaciji i pokušajte ponovo.", cs_CZ="Zatím nebyl pro vašeho uživatele myAudi zadán žádný PIN\nmyAudi. Zadejte PIN pro aplikaci myAudi a zkuste to znovu.", da_DK="Der er indtil nu ikke tildelt en myAudi-pinkode. Opret en pinkode\ni myAudi-appen, og forsøg igen.", de_DE="Bisher wurde keine myAudi PIN vergeben. Bitte lege eine PIN in\nder myAudi App an und versuche es erneut.", el_GR="Μέχρι στιγμής δεν έχει δημιουργηθεί ακόμη myAudi PIN.\nΔημιουργ. ένα PIN στην εφαρμογή myAudi κ. προσπαθ. πάλι.", en_GB="A myAudi PIN has not yet been assigned to your myAudi user.\nPlease set a PIN in the myAudi app and try again.", es_ES="Su usuario myAudi no tiene asignado un PIN myAudi. Cree un PIN\nen la App myAudi y vuelva a intentarlo.", fi_FI="myAudi-käyttäjälle ei ole vielä määritetty myAudi-PIN-koodia.\nAseta PIN myAudi-sovelluksen kautta ja yritä uudelleen.", fr_FR="Vous n'avez pas encore défini de code PIN myAudi. Mémorisez-en\nun dans l'application myAudi et réessayez.", hr_HR="Do sada vašem Audi korisničkom računu nije dodijeljen myAudi\nPIN. Kreirajte PIN u myAudi aplikaciji i pokušajte ponovno.", hu_HU="Eddig nem került megadásra myAudi PIN-kód. Hozz létre egy\nPIN-kódot a myAudi alkalmazásban, és próbáld meg újra.", it_IT="Non è ancora stato assegnato un PIN myAudi al Suo utente\nmyAudi. Creare un PIN nell'app myAudi e riprovare.", nl_NL="Tot nu toe kreeg je geen myAudi PIN voor je myAudi Gebruiker.\nGeef een nieuwe pincode op en probeer opnieuw.", no_NO="Du har ikke laget en myAudi-PIN-kode for din myAudi-bruker\nennå. Lag en PIN-kode i myAudi-appen og prøv igjen.", pl_PL="Do Twojego użytkownika myAudi nie przypisano dotąd kodu PIN\nmyAudi. Utwórz kod PIN w aplikacji myAudi i spróbuj poonownie.", pt_PT="Até agora não foi atribuído um PIN myAudi ao teu utilizador\nmyAudi. Por favor, cria um PIN na myAudi app e volta a tentar.", ro_RO="Până acum nu a fost alocat niciun PIN myAudi. Vă rugăm să creaţi\nun cod PIN în aplicaţia myAudi, apoi reîncercaţi.", ru_RU="Пользователю myAudi еще не присвоен PIN-код. Создайте\nPIN-код в приложении myAudi и повторите попытку.", sk_SK="Doposiaľ nebol priradený žiadny myAudi PIN. Prosím, vytvorte si\nPIN v aplikácii myAudi a pokúste sa o to znova neskôr.", sl_SI="Do sedaj še niste dodelili PIN-kode myAudi. V aplikaciji myAudi\nustvarite PIN-kodo in poskusite znova.", sr_RS="Za vašeg myAudi korisnika do sada nije dodeljen myAudi PIN.\nDefinišite PIN u aplikaciji myAudi i pokušajte ponovo.", sv_SE="Tidigare har ingen Audi Pin-tilldelats din myAudi-användare.\nAnge en PIn i myAudi-appen och försök igen.", tr_TR="Şimdiye kadar hiçbir myAudi PIN atanmadı. Lütfen myAudi App\nuygulamasında bir PIN oluştur ve yeniden dene.", uk_UA="Користувачеві myAudi ще не призначено PIN-код myAudi.\nСтворіть PIN-код у програмі myAudi та повторіть спробу.")
texttool_globals_toast___add_online_user_successfully = TextObject(bs_BA="Dodavanje korisnika je bilo uspješno, ali se nije moglo učitati\nzbog tehničke greške.", cs_CZ="Uživatel byl úspěšně přidán, ale kvůli technické chybě nebyl\nnačten.", da_DK="Bruger blev tilføjet korrekt, men kunne ikke indlæses på grund af\nen teknisk fejl.", de_DE="Der Nutzer wurde erfolgreich hinzugefügt, konnte aber aufgrund\neines technischen Fehlers nicht geladen werden.", el_GR="Ο χρήστης προστέθηκε με επιτυχία, αλλά δεν ήταν εφικτή η\nφόρτωσή του εξαιτίας ενός τεχνικού σφάλματος.", en_GB="The user was added successfully but could not be loaded due to a\ntechnical error.", es_ES="El usuario se ha añadido correctamente, pero no se ha podido\ncargar por un error técnico.", fi_FI="Käyttäjän lisääminen onnistui, mutta sitä ei voitu ladata teknisen\nvirheen vuoksi.", fr_FR="L'utilisateur a été ajouté avec succès mais n'a pas pu être chargé\nen raison d'une erreur technique.", hr_HR="Korisnik je uspješno dodan ali zbog tehničke greške nije mogao\nbiti učitan.", hu_HU="A felhasználó hozzáadása sikeres volt, de technikai hiba miatt\nnem lehetett betölteni.", it_IT="L'utente è stato aggiunto correttamente, ma non è stato\npossibile caricarlo a causa di un errore tecnico.", nl_NL="De gebruiker is succesvol toegevoegd, maar kon vanwege een\ntechnische fout niet worden geladen.", no_NO="Brukeren er lagt til, men kan ikke lastes inn på grunn av en\nteknisk feil.", pl_PL="Użytkownik został pomyślnie dodany, ale nie można go wczytać\nze względu na błąd techniczny.", pt_PT="O utilizador foi adicionado com sucesso, no entanto não pode ser\ncarregado devido a uma falha técnica.", ro_RO="Utilizatorul a fost adăugat cu succes, însă nu a putut fi încărcat\ndin cauza unei erori tehnice.", ru_RU="Пользователь успешно добавлен, но не может быть загружен\nиз-за технической ошибки.", sk_SK="Používateľ bol úspešne pridaný, ale z dôvodu technickej chyby sa\nho nepodarilo načítať.", sl_SI="Uporabnik je bil uspešno dodan, vendar ga zaradi tehnične\nnapake ni bilo mogoče naložiti.", sr_RS="Korisnik je uspešno dodat, ali nije mogao da se učita zbog\ntehničke greške.", sv_SE="Användaren har lagts till, men kunde inte laddas på grund av ett\ntekniskt fel.", tr_TR="Kullanıcı başarılı bir şekilde eklendi ancak teknik bir hata\nnedeniyle yüklenemedi.", uk_UA="Користувач успішно доданий, але не може бути завантажений\nчерез технічну помилку.")
texttool_globals_toast___add_user_error_no_connection = TextObject(bs_BA="Došlo je do greške u povezivanju. Pokušajte ponovo.", cs_CZ="Vyskytla se chyba spojení. Zkuste to prosím znovu.", da_DK="Forbindelsesfejl opstået. Forsøg igen.", de_DE="Es ist ein Verbindungsfehler aufgetreten. Bitte versuche es\nerneut.", el_GR="Προέκυψε σφάλμα σύνδεσης. Προσπαθήστε πάλι.", en_GB="A connection error has occurred. Please try again.", es_ES="Se ha producido un error de conexión. Por favor, inténtelo de\nnuevo.", fi_FI="Yhteysvirhe. Yritä myöhemmin uudelleen.", fr_FR="Une erreur de connexion s'est produite. Veuillez réessayer.", hr_HR="Nastupila je greška u vezi. Pokušajte ponovno.", hu_HU="Kapcsolódási hiba lépett fel. Kérünk, próbáld újra.", it_IT="Si è verificato un errore di collegamento. Si prega di riprovare.", nl_NL="Er is een verbindingsfout opgetreden. Probeer het opnieuw.", no_NO="Det har oppstått en forbindelsesfeil. Prøv på nytt.", pl_PL="Wystąpił błąd połączenia. Proszę spróbować ponownie.", pt_PT="Ocorreu uma falha na ligação. Por favor, volta a tentar.", ro_RO="A apărut o eroare de conectare. Reîncercaţi.", ru_RU="Произошла ошибка подключения. Пожалуйста, попробуйте\nеще раз.", sk_SK="Vyskytla sa chyba pripojenia. Prosím, pokúste sa o to znovu.", sl_SI="Prišlo je do napake v povezavi. Poskusite znova.", sr_RS="Došlo je do greške u povezivanju. Pokušajte ponovo.", sv_SE="Ett anslutningsfel har uppstått. Försök igen.", tr_TR="Bir bağlantı hatası oluştu. Lütfen yeniden dene.", uk_UA="Сталася помилка підключення. Будь ласка, спробуйте ще раз.")
texttool_globals_toast___add_user_error_not_successful = TextObject(bs_BA="Dodavanje korisnika je bilo neuspješno. Pokušajte ponovo\nkasnije.", cs_CZ="Přidání uživatele nebylo úspěšné. Zopakujte prosím znovu\npozději.", da_DK="Tilføjelse af bruger blev ikke gennemført korrekt. Forsøg igen\nsenere.", de_DE="Das Hinzufügen des Nutzers war nicht erfolgreich. Bitte versuche\nes zu einem späteren Zeitpunkt erneut.", el_GR="Η προσθήκη του χρήστη δεν ήταν επιτυχής. Προσπαθήστε πάλι\nαργότερα.", en_GB="The user could not be added. Please try again later.", es_ES="El usuario no se ha podido añadir. Por favor, vuelva a intentarlo\nmás tarde.", fi_FI="Käyttäjän lisääminen epäonnistui. Yritä myöhemmin uudelleen.", fr_FR="L'utilisateur n'a pas pu être ajouté. Veuillez réessayer\nultérieurement.", hr_HR="Dodavanje korisnika nije bilo uspješno. Pokušajte ponovno\nkasnije.", hu_HU="A felhasználó hozzáadása sikertelen volt. Kérünk, próbáld újra\nkésőbb.", it_IT="Non è stato possibile aggiungere l'utente. Si prega di riprovare\npiù tardi.", nl_NL="Het toevoegen van de gebruiker is niet gelukt. Probeer het later\nopnieuw.", no_NO="Kan ikke legge til brukeren. Prøv igjen senere.", pl_PL="Dodawanie użytkownika nie powiodło się. Proszę spróbować\nponownie później.", pt_PT="A introdução do utilizador falhou. Por favor, volte a tentar mais\ntarde.", ro_RO="Adăugarea utilizatorului a eşuat. Reîncercaţi mai târziu.", ru_RU="Не удалось добавить пользователя. Пожалуйста, повторите\nпопытку позже.", sk_SK="Pridanie používateľa nebolo úspešné. Prosím, pokúste sa o to\nznovu neskôr.", sl_SI="Dodajanje uporabnika ni bilo uspešno. Poskusite znova pozneje.", sr_RS="Dodavanje korisnika je bilo neuspešno. Pokušajte ponovo kasnije.", sv_SE="Användaren kunde inte läggas till. Försök igen senare.", tr_TR="Kullanıcının eklenmesi başarısız oldu. Lütfen daha sonra yeniden\ndene.", uk_UA="Не вдалося додати користувача. Будь ласка, спробуйте\nпізніше.")
texttool_globals_toast___add_user_password_locked = TextObject(bs_BA="Prijava nije moguća. Vaš myAudi korisnik je blokiran. Deblokirajte\nkorisnika na myAudi portalu i pokušajte ponovo.", cs_CZ="Přihlášení není možné. Váš uživatel myAudi je zablokován.\nOdblokujte prosím uživatele v portálu myAudi a zkuste to znovu.", da_DK="Login ikke mulig. Din myAudi-bruger er spærret. Ophæv\nspærringen for brugeren på myAudi-portalen, og forsøg igen.", de_DE="Anmeldung ist nicht möglich. Dein myAudi Nutzer ist gesperrt.\nEntsperre den Nutzer im myAudi Portal.", el_GR="Σύνδ. (log in) μη εφικτή. Λογ/μός σας χρήστη myAudi φραγ- μέν.\nΑναιρ. φραγή λογ/μού χρήστη στ. διαδ. πύλη myAudi.", en_GB="It is not possible to log in. Your myAudi user is locked. Please\nunlock the user in the myAudi portal and try again.", es_ES="No se puede iniciar sesión. Su usuario myAudi está bloqueado.\nDesbloquéelo en el portal myAudi y vuelva a intentarlo.", fi_FI="Kirjautuminen ei ole mahdollista. myAudi-käyttäjätilisi on\nlukittu. Vapauta käyttäjän lukitus myAudi-portaalin kautta.", fr_FR="La connexion est impossible. Votre profil utilisateur myAudi est\nbloqué. Veuillez le débloquer sur le portail myAudi et réessayez.", hr_HR="Prijava nije moguća. Vaš myAudi korisnički račun je blokiran.\nDeblokirajte korisnički račun na myAudi portalu.", hu_HU="A bejelentkezés nem lehets. A myAudi felhasználód le van tiltva.\nSzüntesd meg a felhaszn letiltását a myAudi portálon.", it_IT="Login impossibile. L'utente myAudi è bloccato. Sbloccare l'utente\nsul portale myAudi e riprovare.", nl_NL="Aanmelden is niet mogelijk. Je myAudi gebruiker is geblokkeerd.\nDeblokkeer de gebruiker in het myAudi portaal.", no_NO="Kan ikke logge på. myAudi-brukeren din er sperret. Opphev\nbrukersperren i myAudi-portalen og prøv igjen.", pl_PL="Nie można się zalogować. Twój użytkownik myAudi jest\nzablokowany. Odblokuj użytkownika na portalu myAudi.", pt_PT="O login não é possível. O teu utilizador myAudi está\nbloqueado.Desbloqueia o utilizador no portal myAudi.", ro_RO="Autentificarea nu este posibilă. Utilizatorul dvs. myAudi este\nblocat. Deblocaţi utilizatorul în portalul myAudi.", ru_RU="Рег-ция невозможна. Пользователь myAudi заблокирован.\nРазблокируйте пользователя на портале myAudi.", sk_SK="Prihlásenie nie je možné. Váš používateľ myAudi je zablokovaný.\nOdblokujte používateľa na portáli myAudi.", sl_SI="Prijava ni mogoča. Uporabnik myAudi je blokiran. Uporabnika\nodklenite na portalu myAudi in poskusite znova.", sr_RS="Prijava nije moguća. Vaš myAudi korisnik je blokiran. Deblokirajte\nkorisnika na myAudi portalu i pokušajte ponovo.", sv_SE="Inloggning är inte möjlig. Din myAudi-användare är spärrad. Lås\nupp användaren i myAudi-portalen och försök igen.", tr_TR="Oturum açma mümkün değil. myAudi kullanıcın engellenmiş.\nmyAudi portalında kullanıcının engellemesini kaldır.", uk_UA="Реєстрація неможлива. Ваш користувач myAudi заблокований.\nРозблокуйте користувача на порталі myAudi і повторіть спробу.")
texttool_globals_toast___add_user_warn_maximum_nr_of_users_reached = TextObject(bs_BA="Dostignut je maksimalni broj korisnika.", cs_CZ="Byl dosažen maximální počet uživatelů.", da_DK="Maksimalt antal brugere blev nået.", de_DE="Die maximale Anzahl an Nutzern wurde erreicht.", el_GR="Επιτεύχθηκε ο μέγιστος αριθμός χρηστών.", en_GB="The maximum number of users has been reached.", es_ES="Se ha alcanzado el número máximo de usuarios.", fi_FI="Enimmäismäärä käyttäjiä on saavutettu.", fr_FR="Le nombre maximum d'utilisateurs est atteint.", hr_HR="Dostignut je maksimalan broj korisnika.", hu_HU="A felhasználók maximális száma elérve.", it_IT="È stato raggiunto il numero massimo di utenti.", nl_NL="Het maximale aantal gebruikers is bereikt.", no_NO="Maksimalt antall brukere er nådd.", pl_PL="Osiągnięto maksymalną liczbę użytkowników.", pt_PT="Foi atingido o número máximo de utilizadores.", ro_RO="Număr maxim de utilizatori atins.", ru_RU="Достигнуто максимальное количество пользователей.", sk_SK="Dosiahol sa maximálny počet používateľov.", sl_SI="Doseženo je bilo največje število uporabnikov.", sr_RS="Dostignut je maksimalni broj korisnika.", sv_SE="Det maximala antalet användare har uppnåtts.", tr_TR="Maksimum kullanıcı sayısına ulaşıldı.", uk_UA="Досягнуто максимальної кількості користувачів.")
texttool_globals_toast___assign_key_error_assignment_blocked_active_user = TextObject(bs_BA="Ključ je već povezan s vašim korisnikom.", cs_CZ="Klíč již byl propojen s Vaším uživatelem.", da_DK="Nøglen er allerede blevet forbundet med din bruger.", de_DE="Der Schlüssel wurde bereits mit deinem Nutzer verknüpft.", el_GR="Το κλειδί έχει ήδη συνδεθεί με τον λογαριασμό χρήστη σας.", en_GB="The key is already linked to your user.", es_ES="La llave se ha emparejado con su usuario.", fi_FI="Avain on jo yhdistetty käyttäjätiliisi.", fr_FR="La clé est déjà associée à votre profil utilisateur.", hr_HR="Ključ je već povezan s vašim korisničkim računom.", hu_HU="A kulcs már össze van kapcsolva a felhasználóddal.", it_IT="La chiave è già stata associata a questo utente.", nl_NL="De sleutel is al aan je gebruiker gekoppeld.", no_NO="Nøkkelen er allerede tilknyttet brukeren din.", pl_PL="Ten klucz został już powiązany z Tobą jako użytkownikiem.", pt_PT="A chave já foi associada ao teu utilizador.", ro_RO="Cheia a fost deja asociată cu utilizatorul dumneavoastră.", ru_RU="Ключ уже привязан к вашему пользователю.", sk_SK="Kľúč už bol priradený tvojmu používateľskému účtu.", sl_SI="Ključ je že bil povezan z vašim uporabnikom.", sr_RS="Ključ je već povezan sa Vašim korisnikom.", sv_SE="Nyckeln har redan kopplats till din användare.", tr_TR="Anahtar, kullanıcına zaten bağlandı.", uk_UA="Ключ вже пов'язаний з вашим користувачем.")
texttool_globals_toast___assign_key_error_assignment_blocked_primary_user = TextObject(bs_BA="Povezivanje ključa s vama nije bilo moguće, jer se radi o\nosnovnom uređaju koji je fiksno povezan s glavnim korisnikom.", cs_CZ="Klíč nelze s Vámi propojit, protože se jedná o hlavní zařízení,\nkteré je pevně propojeno s hlavním uživatelem.", da_DK="Nøgle kunne ikke forbindes, da det drejer sig om det primære\napparat, som er fast forbundet med den primære bruger.", de_DE="Der Schlüssel konnte nicht verknüpft werden, da es sich um das\nHauptgerät handelt, das fest mit dem Hauptnutzer verknüpft ist.", el_GR="Δεν ήταν εφικτή η σύνδ. τ. κλειδιού με εσάς, διότι πρόκειται γ. τ.\nκύρια συσκευή, η οπ. είναι σταθερά συνδεδ.η με τον βασ. χρήστη.", en_GB="The key cannot be linked to you as this is a main device that\nshares a fixed connection to the key user.", es_ES="La llave no se ha podido emparejar porque se trata del\ndispositivo principal y está emparejada con el usuario principal.", fi_FI="Avainta ei voitu yhdistää sinuun, koska kyseessä on päälaite, joka\non yhdistetty kiinteästi pääkäyttäjään.", fr_FR="La clé n'a pas pu être associée car il s'agit du périphériq. principal\nqui est associé de manière fixe au profil utilisateur principal.", hr_HR="Ključ nije bilo moguće povezati s vama jer se radi o glavnom\nuređaju koji je fiksno povezan s glavnim korisnikom.", hu_HU="A kulcsot nem sikerült összekapcsolni, mert a főkészülékről van\nszó, amely állandóan a főfelhasználóhoz van kapcsolva.", it_IT="Impossibile associare la chiave perché si tratta del dispositivo\nprincipale, associato in modo permanente all'utente principale.", nl_NL="De sleutel kon niet worden gekoppeld, omdat het om het\nhoofdapparaat gaat dat aan de hoofdgebruiker is gekoppeld.", no_NO="Kan ikke knytte nøkkelen til deg. Det er fordi det gjelder\nhovedenheten som er permanent tilknyttet hovedbrukeren.", pl_PL="Nie można powiązać z Tobą klucza, ponieważ jest to urządzenie\ngłówne, powiązane na stałe z głównym użytkownikiem.", pt_PT="A chave não pode ser associada, pois trata-se do ap. principal que\nestá associado de forma definitiva ao utilizador principal.", ro_RO="Cheia nu a putut fi asociată, deoarece este vorba despre dispozit.\nprincipal, care este asociat ferm cu utilizatorul principal.", ru_RU="Ключ не может быть привязан к вам, так как это основное\nустройство, которое привязано к основному пользователю.", sk_SK="Kľúč nebolo možné priradiť k vám, pretože sa jedná o hlavné\nzariadenie, ktoré je trvalo priradené k hlavnému používateľovi.", sl_SI="Ključa ni bilo mogoče povezati z vami, ker gre za glavno napravo,\nki je stalno povezana z glavnim uporabnikom.", sr_RS="Povezivanje ključa sa Vama nije bilo moguće, jer je reč o glavnom\nuređaju koji je fiksno povezan sa glavnim korisnikom.", sv_SE="Nyckeln kunde inte kopplas till dig eftersom det rör sig om\nhuvudenheten som är permanent kopplad till huvudanvändaren.", tr_TR="Anahtar sana bağlanamadı, çünkü burada ana kullanıcıya kalıcı\nolarak bağlı olan ana cihaz söz konusudur.", uk_UA="Ключ не може бути пов'язаний, оскільки це основ. пристрій,\nякий є невід'ємно пов'язаним з основ. користувачем.")
texttool_globals_toast___assign_key_error_not_successful = TextObject(bs_BA="Ključ se nije mogao povezati. Pokušajte ponovo kasnije.", cs_CZ="Klíč se nepodařilo propojit. Zkuste to prosím znovu později.", da_DK="Nøgle kunne ikke forbindes. Forsøg igen senere.", de_DE="Der Schlüssel konnte nicht verknüpft werden. Bitte versuche es\nspäter nochmal.", el_GR="Δεν ήταν εφικτή η σύνδεση του κλειδιού. Προσπαθήστε πάλι\nαργότερα.", en_GB="Unable to link key. Please try again later.", es_ES="La llave no se ha podido emparejar. Por favor, inténtelo de nuevo\nmás tarde.", fi_FI="Avainta ei voitu yhdistää. Yritä myöhemmin uudelleen.", fr_FR="La clé n'a pas pu être associée. Veuillez réessayer ultérieurement.", hr_HR="Ključ nije povezan. Pokušajte ponovno kasnije.", hu_HU="A kulcsot nem sikerült összekapcsolni. Próbáld újra később.", it_IT="Non è stato possibile collegare la chiave. Si prega di riprovare più\ntardi.", nl_NL="De sleutel kon niet worden gekoppeld. Probeer het later nog\neens.", no_NO="Kan ikke tilknytte nøkkelen. Prøv igjen senere.", pl_PL="Nie można powiązać kluczyka. Spróbuj ponownie później.", pt_PT="Não foi possível associar a chave. Por favor, volta a tentar mais\ntarde.", ro_RO="Cheia nu a putut fi asociată. Reîncercaţi mai târziu.", ru_RU="Не удалось привязать ключ. Пожалуйста, повторите попытку\nпозже.", sk_SK="Kľúč sa nepodarilo prepojiť. Prosím, pokúste sa o to znovu\nneskôr.", sl_SI="Ključa ni bilo mogoče povezati. Poskusite znova pozneje.", sr_RS="Povezivanje ključa nije bilo moguće. Pokušajte ponovo kasnije.", sv_SE="Nyckeln kunde inte kopplas. Försök igen senare.", tr_TR="Anahtar bağlanamadı. Lütfen daha sonra tekrar dene.", uk_UA="Не вдалося прив'язати ключ. Будь ласка, повторіть спробу\nпізніше.")
